export enum InteractionMode {
  QA = 'QA',
  EXPLAIN = 'EXPLAIN',
  QUIZ = 'QUIZ',
  TEACH_ME = 'TEACH_ME'
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
  mode?: InteractionMode;
}

export interface PDFData {
  name: string;
  base64: string;
  mimeType: string;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { InteractionMode } from "../types";

const SYSTEM_INSTRUCTION = `
You are "Nebras" (نبراس), a brilliant, friendly, and witty Iraqi Academic Tutor.
Your mission is to help students understand their curriculum from uploaded PDF files.

Operational Modes:
1. Q&A Mode: Answer student questions accurately based on the PDF.
2. Explain Mode (شرح مبسط): Simplify complex concepts using analogies and Iraqi dialect (سالفة) to make it relatable.
3. Quiz Mode (اختبار): Generate 3-5 challenging MCQs from the PDF.
4. Reverse Teaching Mode (أني أشرحلك): Listen to the student's explanation. Identify what they got right, point out misconceptions gently, and ask follow-up questions.

Personality:
- Use a mix of Modern Standard Arabic and Iraqi dialect (e.g., "هلا بيك", "هسة أفهمك", "تدلل").
- Always cite the page number if possible.
- Be encouraging and supportive.
`;

export const getGeminiResponse = async (
  prompt: string,
  pdf: { base64: string; mimeType: string } | null,
  mode: InteractionMode
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  let modeInstruction = "";
  switch (mode) {
    case InteractionMode.EXPLAIN:
      modeInstruction = "اشرح لي هذا الموضوع بأسلوب عراقي بسيط وقصة (سالفة) لتقريب الفكرة.";
      break;
    case InteractionMode.QUIZ:
      modeInstruction = "سوي لي اختبار (Quiz) من 3 اسئلة خيارات متعددة عن هذا الفصل.";
      break;
    case InteractionMode.TEACH_ME:
      modeInstruction = "أنا راح أشرحلك الموضوع، وأنت صلح لي فهمي وشوفني وين خطأت.";
      break;
    default:
      modeInstruction = "";
  }

  const parts: any[] = [{ text: prompt + "\n" + modeInstruction }];

  if (pdf) {
    parts.unshift({
      inlineData: {
        data: pdf.base64,
        mimeType: pdf.mimeType
      }
    });
  }

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return result.text || "عذراً، صار خلل بسيط. جرب مرة ثانية.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "ما كدرت أتواصل وية خوادمي، تأكد من ملف الـ PDF أو اتصالك.";
  }
};

