export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { PDFData } from '../types';
import { encode, decode, decodeAudioData } from '../services/audioUtils';

interface LiveModeOverlayProps {
  currentPdf: PDFData | null;
  onClose: () => void;
  onTranscription: (text: string, role: 'user' | 'model') => void;
}

const LiveModeOverlay: React.FC<LiveModeOverlayProps> = ({ currentPdf, onClose, onTranscription }) => {
  const [isConnecting, setIsConnecting] = useState(true);
  const [isListening, setIsListening] = useState(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<{ input: AudioContext; output: AudioContext } | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const transcriptionRef = useRef<{ user: string; model: string }>({ user: '', model: '' });

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

    const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    audioContextRef.current = { input: inputCtx, output: outputCtx };

    let mediaStream: MediaStream;

    const startSession = async () => {
      try {
        mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
            },
            systemInstruction: `أنت نبراس، مدرس خصوصي عراقي. جاوب بصوتك بلهجة عراقية محببة. الملف المرفق هو مادة الطالب.`,
            inputAudioTranscription: {},
            outputAudioTranscription: {},
          },
          callbacks: {
            onopen: () => {
              setIsConnecting(false);
              setIsListening(true);

              const source = inputCtx.createMediaStreamSource(mediaStream);
              const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) {
                  int16[i] = inputData[i] * 32768;
                }
                const pcmBlob = {
                  data: encode(new Uint8Array(int16.buffer)),
                  mimeType: 'audio/pcm;rate=16000',
                };
                sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
              };

              source.connect(scriptProcessor);
              scriptProcessor.connect(inputCtx.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
              // Handle Transcriptions
              if (message.serverContent?.inputTranscription) {
                transcriptionRef.current.user += message.serverContent.inputTranscription.text;
              }
              if (message.serverContent?.outputTranscription) {
                transcriptionRef.current.model += message.serverContent.outputTranscription.text;
              }
              if (message.serverContent?.turnComplete) {
                if (transcriptionRef.current.user) onTranscription(transcriptionRef.current.user, 'user');
                if (transcriptionRef.current.model) onTranscription(transcriptionRef.current.model, 'model');
                transcriptionRef.current = { user: '', model: '' };
              }

              // Handle Audio Output
              const audioBase64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
              if (audioBase64) {
                const buffer = await decodeAudioData(decode(audioBase64), outputCtx, 24000, 1);
                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputCtx.destination);

                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
                source.onended = () => sourcesRef.current.delete(source);
              }

              if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
              }
            },
            onclose: () => onClose(),
            onerror: (e) => console.error("Live API Error:", e),
          },
        });

        sessionRef.current = await sessionPromise;

        // Send initial context if PDF exists
        if (currentPdf) {
            sessionRef.current.sendRealtimeInput({
                media: { data: currentPdf.base64, mimeType: currentPdf.mimeType }
            });
        }

      } catch (err) {
        console.error("Failed to start live session:", err);
        onClose();
      }
    };

    startSession();

    return () => {
      mediaStream?.getTracks().forEach(t => t.stop());
      sessionRef.current?.close();
      audioContextRef.current?.input.close();
      audioContextRef.current?.output.close();
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-blue-600/95 backdrop-blur-xl flex flex-col items-center justify-center p-6 text-white text-center">
      <button 
        onClick={onClose}
        className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 transition-all"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
        </svg>
      </button>

      <div className="relative mb-12">
        <div className={`w-32 h-32 bg-white rounded-full flex items-center justify-center text-5xl shadow-2xl relative z-10 ${isListening ? 'animate-pulse' : ''}`}>
          🎙️
        </div>
        {isListening && (
          <>
            <div className="absolute inset-0 w-full h-full bg-white rounded-full animate-ping opacity-20"></div>
            <div className="absolute inset-0 w-full h-full bg-white rounded-full animate-ping opacity-10" style={{ animationDelay: '0.5s' }}></div>
          </>
        )}
      </div>

      <h2 className="text-3xl font-bold mb-4">
        {isConnecting ? 'جاري الاتصال بنبراس...' : 'سولف، نبراس يسمعك'}
      </h2>
      <p className="text-blue-100 max-w-xs mb-8">
        نبراس هسة كاعد يسمعك، تكدر تسأله أي شي عن المادة وهو يجاوبك فوراً بصوته.
      </p>

      <div className="flex gap-4">
        <div className="h-1 w-12 bg-white/20 rounded-full overflow-hidden">
            <div className="h-full bg-white animate-[shimmer_2s_infinite]"></div>
        </div>
      </div>

      <style>{`
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
      `}</style>
    </div>
  );
};

