        <ModeBadge mode={InteractionMode.TEACH_ME} label="أني أشرحلك" icon="🎓" />
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
        {messages.length === 0 && !currentPdf && (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6">
            <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center text-4xl animate-bounce">
              📚
            </div>
            <div>
              <h2 className="text-2xl font-bold text-slate-800 mb-2">هلا بيك بـ "نبراس"!</h2>
              <p className="text-slate-500 max-w-sm">ارفع كتابك أو ملزمتك بصيغة PDF وخلي نبدأ ندرس سوا بذكاء.</p>
            </div>
            <label className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl font-bold shadow-lg shadow-blue-200 cursor-pointer transition-all active:scale-95 flex items-center gap-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              ارفع الملف الآن
              <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
