import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { PDFData } from './types';

const App: React.FC = () => {
  const [currentPdf, setCurrentPdf] = useState<PDFData | null>(null);

  // Load PDF from localStorage on mount
  useEffect(() => {
    const savedPdf = localStorage.getItem('nebras_current_pdf');
    if (savedPdf) {
      try {
        setCurrentPdf(JSON.parse(savedPdf));
      } catch (e) {
        console.error("Failed to load saved PDF", e);
      }
    }
  }, []);

  const handlePdfUpload = (pdf: PDFData) => {
    setCurrentPdf(pdf);
    localStorage.setItem('nebras_current_pdf', JSON.stringify(pdf));
  };

  const handleClearPdf = () => {
    if (window.confirm('هل أنت متأكد من إغلاق هذا الملف؟ ستبدأ جلسة جديدة وسيتم مسح السجل.')) {
      setCurrentPdf(null);
      localStorage.removeItem('nebras_current_pdf');
      localStorage.removeItem('nebras_chat_history');
      // Force reload to clear chat interface state if necessary, 
      // though ChatInterface handles its own state.
      window.location.reload();
    }
  };

  return (
    <Layout>
      <div className="flex w-full h-[calc(100vh-64px)] overflow-hidden">
        <Sidebar currentPdf={currentPdf} onClear={handleClearPdf} />
        <ChatInterface currentPdf={currentPdf} onPdfUpload={handlePdfUpload} />
      </div>
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { InteractionMode, ChatMessage, PDFData } from '../types';
import { getGeminiResponse } from '../services/geminiService';
import LiveModeOverlay from './LiveModeOverlay';

interface ChatInterfaceProps {
  currentPdf: PDFData | null;
  onPdfUpload: (pdf: PDFData) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentPdf, onPdfUpload }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeMode, setActiveMode] = useState<InteractionMode>(InteractionMode.QA);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Load messages from localStorage on mount
  useEffect(() => {
    const savedMessages = localStorage.getItem('nebras_chat_history');
    if (savedMessages) {
      try {
        const parsed = JSON.parse(savedMessages);
        // Convert string timestamps back to Date objects
        const formatted = parsed.map((m: any) => ({
          ...m,
          timestamp: new Date(m.timestamp)
        }));
        setMessages(formatted);
      } catch (e) {
        console.error("Failed to parse chat history", e);
      }
    }
  }, []);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('nebras_chat_history', JSON.stringify(messages));
    }
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    scrollToBottom();
  }, [isLoading]);

  const handleSendMessage = async (e?: React.FormEvent, customPrompt?: string) => {
    e?.preventDefault();
    const finalInput = customPrompt || input;
    if (!finalInput.trim() && !customPrompt) return;

    const userMessage: ChatMessage = {
      role: 'user',
      content: finalInput,
      timestamp: new Date(),
      mode: activeMode
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const responseText = await getGeminiResponse(
      finalInput,
      currentPdf ? { base64: currentPdf.base64, mimeType: currentPdf.mimeType } : null,
      activeMode
    );

    const modelMessage: ChatMessage = {
      role: 'model',
      content: responseText,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, modelMessage]);
    setIsLoading(false);
  };

  const handleLiveTranscription = (text: string, role: 'user' | 'model') => {
    const newMessage: ChatMessage = {
      role,
      content: text,
      timestamp: new Date(),
    };
    setMessages(prev => [...prev, newMessage]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        onPdfUpload({
          name: file.name,
          base64: base64,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const ModeBadge = ({ mode, label, icon }: { mode: InteractionMode; label: string; icon: string }) => (
    <button
      onClick={() => setActiveMode(mode)}
      className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-all ${
        activeMode === mode
          ? 'bg-blue-600 text-white shadow-md'
          : 'bg-white text-slate-600 hover:bg-slate-100 border border-slate-200'
      }`}
    >
      <span>{icon}</span>
      {label}
    </button>
  );

  return (
    <div className="flex flex-col flex-1 h-full bg-white relative">
      {isLiveMode && (
        <LiveModeOverlay 
          currentPdf={currentPdf} 
          onClose={() => setIsLiveMode(false)}
          onTranscription={handleLiveTranscription}
        />
      )}

      {/* Mode Selection */}
      <div className="bg-white/80 backdrop-blur-md border-b border-slate-100 p-4 sticky top-0 z-10 flex gap-2 overflow-x-auto no-scrollbar">
        <ModeBadge mode={InteractionMode.QA} label="أسأل سؤال" icon="❓" />
        <ModeBadge mode={InteractionMode.EXPLAIN} label="اشرح لي" icon="💡" />
        <ModeBadge mode={InteractionMode.QUIZ} label="اختبرني" icon="📝" />
        <ModeBadge mode={InteractionMode.TEACH_ME} label="أني أشرحلك" icon="🎓" />
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
        {messages.length === 0 && !currentPdf && (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6">
            <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center text-4xl animate-bounce">
              📚
            </div>
            <div>
              <h2 className="text-2xl font-bold text-slate-800 mb-2">هلا بيك بـ "نبراس"!</h2>
              <p className="text-slate-500 max-w-sm">ارفع كتابك أو ملزمتك بصيغة PDF وخلي نبدأ ندرس سوا بذكاء.</p>
            </div>
            <label className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl font-bold shadow-lg shadow-blue-200 cursor-pointer transition-all active:scale-95 flex items-center gap-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              ارفع الملف الآن
              <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
            </label>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}
          >
            <div
              className={`max-w-[85%] md:max-w-[70%] p-4 rounded-2xl shadow-sm border ${
                msg.role === 'user'
                  ? 'bg-slate-100 border-slate-200 text-slate-800'
                  : 'bg-blue-50 border-blue-100 text-slate-800 leading-relaxed font-medium'
              }`}
            >
              <div className="flex items-center gap-2 mb-2">
                <span className="text-xs font-bold uppercase tracking-wider opacity-50">
                  {msg.role === 'user' ? 'أنت' : 'نبراس'}
                </span>
                <span className="text-[10px] opacity-40">
                  {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
              <div className="whitespace-pre-wrap text-base">
                {msg.content}
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-end">
            <div className="bg-blue-50 border border-blue-100 p-4 rounded-2xl flex items-center gap-3">
              <div className="flex gap-1">
                <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
              </div>
              <span className="text-sm text-blue-600 font-medium italic">نبراس ديفكر...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Form */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="max-w-4xl mx-auto flex gap-3 items-center">
          <button 
            type="button"
            onClick={() => setIsLiveMode(true)}
            className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-100 hover:scale-105 active:scale-95 transition-all flex-shrink-0 relative group"
            title="تحدث مع نبراس مباشرة"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
            <span className="absolute -top-12 left-1/2 -translate-x-1/2 bg-slate-800 text-white text-[10px] py-1 px-2 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
              سولف وية نبراس
            </span>
          </button>

          <form onSubmit={handleSendMessage} className="flex-1 flex gap-3">
            <div className="flex-1 relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder={
                  activeMode === InteractionMode.TEACH_ME
                    ? "اشرح لي الي فهمته وهسة أصلحلك..."
                    : "اكتب سؤالك هسة..."
                }
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-4 px-6 pr-14 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-inner text-lg"
                disabled={isLoading}
              />
              <label className="absolute left-4 top-1/2 -translate-y-1/2 cursor-pointer hover:bg-slate-200 p-2 rounded-xl transition-all">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                </svg>
                <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
              </label>
            </div>
            <button
              type="submit"
              disabled={isLoading || !input.trim()}
              className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-bold shadow-lg hover:bg-blue-700 disabled:bg-slate-300 transition-all flex items-center gap-2"
            >
              <span>إرسال</span>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 transform rotate-180" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </form>
        </div>
        {currentPdf && (
          <div className="max-w-4xl mx-auto mt-2 flex items-center gap-2 text-[10px] text-slate-400">
            <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
            جاري العمل على: {currentPdf.name}
          </div>
        )}
      </div>
    </div>
  );
};

