import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { InteractionMode } from "../types";

const SYSTEM_INSTRUCTION = `
You are "Nebras" (نبراس), a brilliant, friendly, and witty Iraqi Academic Tutor.
Your mission is to help students understand their curriculum from uploaded PDF files.

Operational Modes:
1. Q&A Mode: Answer student questions accurately based on the PDF.
2. Explain Mode (شرح مبسط): Simplify complex concepts using analogies and Iraqi dialect (سالفة) to make it relatable.
3. Quiz Mode (اختبار): Generate 3-5 challenging MCQs from the PDF.
4. Reverse Teaching Mode (أني أشرحلك): This is your unique feature. When the student explains a topic to you:
   - Listen carefully to their explanation.
   - Identify exactly what they got right to boost their confidence.
   - Gently point out any missing information or misconceptions in a supportive Iraqi way.
   - Ask a clever follow-up question to ensure they've fully mastered the concept.

Personality:
- Use a mix of Modern Standard Arabic and Iraqi dialect (e.g., "عاشت إيدك", "هلا بيك", "هسة أفهمك", "تدلل", "خوش حجي").
- Always cite the page number if possible.
- Be encouraging, supportive, and act like a real Iraqi tutor sitting next to the student.
`;

export const getGeminiResponse = async (
  prompt: string,
  pdf: { base64: string; mimeType: string } | null,
  mode: InteractionMode
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  let modeInstruction = "";
  switch (mode) {
    case InteractionMode.EXPLAIN:
      modeInstruction = "اشرح لي هذا الموضوع بأسلوب عراقي بسيط وقصة (سالفة) لتقريب الفكرة.";
      break;
    case InteractionMode.QUIZ:
      modeInstruction = "سوي لي اختبار (Quiz) من 3 اسئلة خيارات متعددة عن هذا الفصل.";
      break;
    case InteractionMode.TEACH_ME:
      modeInstruction = "أنا راح أشرحلك الموضوع اللي قريته، أنت صلح لي فهمي، كولي شنو الصح وشنو الغلط بوضوح وبأسلوبك العراقي الحلو، واسألني سؤال بنهاية كلامك يختبر ذكائي.";
      break;
    default:
      modeInstruction = "";
  }

  const parts: any[] = [{ text: prompt + "\n" + modeInstruction }];

  if (pdf) {
    parts.unshift({
      inlineData: {
        data: pdf.base64,
        mimeType: pdf.mimeType
      }
    });
  }

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return result.text || "عذراً، صار خلل بسيط. جرب مرة ثانية.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "ما كدرت أتواصل وية خوادمي، تأكد من ملف الـ PDF أو اتصالك.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { InteractionMode, ChatMessage, PDFData } from '../types';
import { getGeminiResponse } from '../services/geminiService';
import LiveModeOverlay from './LiveModeOverlay';

interface ChatInterfaceProps {
  currentPdf: PDFData | null;
  onPdfUpload: (pdf: PDFData) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentPdf, onPdfUpload }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeMode, setActiveMode] = useState<InteractionMode>(InteractionMode.QA);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Load messages from localStorage on mount
  useEffect(() => {
    const savedMessages = localStorage.getItem('nebras_chat_history');
    if (savedMessages) {
      try {
        const parsed = JSON.parse(savedMessages);
        const formatted = parsed.map((m: any) => ({
          ...m,
          timestamp: new Date(m.timestamp)
        }));
        setMessages(formatted);
      } catch (e) {
        console.error("Failed to parse chat history", e);
      }
    }
  }, []);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('nebras_chat_history', JSON.stringify(messages));
    }
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    scrollToBottom();
  }, [isLoading]);

  const handleSendMessage = async (e?: React.FormEvent, customPrompt?: string) => {
    e?.preventDefault();
    const finalInput = customPrompt || input;
    if (!finalInput.trim() && !customPrompt) return;

    const userMessage: ChatMessage = {
      role: 'user',
      content: finalInput,
      timestamp: new Date(),
      mode: activeMode
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const responseText = await getGeminiResponse(
      finalInput,
      currentPdf ? { base64: currentPdf.base64, mimeType: currentPdf.mimeType } : null,
      activeMode
    );

    const modelMessage: ChatMessage = {
      role: 'model',
      content: responseText,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, modelMessage]);
    setIsLoading(false);
  };

  const handleLiveTranscription = (text: string, role: 'user' | 'model') => {
    const newMessage: ChatMessage = {
      role,
      content: text,
      timestamp: new Date(),
    };
    setMessages(prev => [...prev, newMessage]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        onPdfUpload({
          name: file.name,
          base64: base64,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const ModeBadge = ({ mode, label, icon }: { mode: InteractionMode; label: string; icon: string }) => (
    <button
      onClick={() => setActiveMode(mode)}
      className={`flex items-center gap-2 px-4 py-2.5 rounded-2xl text-sm font-bold transition-all duration-300 border-2 ${
        activeMode === mode
          ? 'bg-blue-600 border-blue-600 text-white shadow-lg scale-105 shadow-blue-200'
          : 'bg-white border-slate-100 text-slate-600 hover:border-blue-200 hover:bg-blue-50'
      }`}
    >
      <span className="text-lg">{icon}</span>
      {label}
    </button>
  );

  return (
    <div className="flex flex-col flex-1 h-full bg-[#f8fafc] relative">
      {isLiveMode && (
        <LiveModeOverlay 
          currentPdf={currentPdf} 
          onClose={() => setIsLiveMode(false)}
          onTranscription={handleLiveTranscription}
        />
      )}

      {/* Mode Selection Bar */}
      <div className="bg-white/90 backdrop-blur-lg border-b border-slate-200 p-4 sticky top-0 z-10 flex gap-3 overflow-x-auto no-scrollbar shadow-sm">
        <ModeBadge mode={InteractionMode.QA} label="أسأل سؤال" icon="❓" />
        <ModeBadge mode={InteractionMode.EXPLAIN} label="اشرح لي" icon="💡" />
        <ModeBadge mode={InteractionMode.QUIZ} label="اختبرني" icon="📝" />
        <ModeBadge mode={InteractionMode.TEACH_ME} label="أني أشرحلك" icon="🎓" />
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-8 custom-scrollbar">
        {messages.length === 0 && !currentPdf && (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-6 animate-in fade-in zoom-in duration-700">
            <div className="relative">
                <div className="absolute inset-0 bg-blue-500 rounded-full blur-2xl opacity-20 animate-pulse"></div>
                <div className="w-28 h-28 bg-white border-4 border-blue-500 rounded-3xl flex items-center justify-center text-6xl shadow-xl relative z-10">
                  📚
                </div>
            </div>
            <div>
              <h2 className="text-3xl font-bold text-slate-800 mb-2">هلا بيك بـ "نبراس"!</h2>
              <p className="text-slate-500 max-w-sm text-lg leading-relaxed font-medium">ارفع كتابك أو ملزمتك بصيغة PDF وخلي نبدأ ندرس سوا بذكاء وبلهجة عراقية.</p>
            </div>
            <label className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-5 rounded-3xl font-bold shadow-xl shadow-blue-200 cursor-pointer transition-all active:scale-95 flex items-center gap-3 text-lg group">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:bounce" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              ارفع الملف الآن
              <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
            </label>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`flex items-end gap-3 ${msg.role === 'user' ? 'flex-row-reverse justify-start' : 'flex-row justify-start'} animate-in slide-in-from-bottom-4 duration-500`}
          >
            {/* Avatar */}
            <div className={`w-10 h-10 rounded-2xl flex-shrink-0 flex items-center justify-center shadow-md font-bold text-lg ${
                msg.role === 'user' ? 'bg-slate-800 text-white' : 'bg-blue-600 text-white'
            }`}>
                {msg.role === 'user' ? 'أ' : 'ن'}
            </div>

            {/* Message Bubble Wrapper */}
            <div className={`flex flex-col max-w-[85%] md:max-w-[70%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div
                    className={`p-5 rounded-3xl shadow-sm border transition-all ${
                        msg.role === 'user'
                        ? 'bg-white border-slate-200 text-slate-800 rounded-tr-none'
                        : 'bg-gradient-to-br from-blue-600 to-blue-700 border-blue-500 text-white rounded-tl-none shadow-lg shadow-blue-100'
                    }`}
                >
                    <div className="whitespace-pre-wrap text-[16px] md:text-[17px] leading-relaxed font-medium">
                        {msg.content}
                    </div>
                </div>

                {/* Time & Role Label */}
                <div className={`mt-1.5 flex items-center gap-2 px-1 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
                        {msg.role === 'user' ? 'الطالب' : 'نبراس المدرس'}
                    </span>
                    <span className="text-[10px] text-slate-300 font-medium">
                        {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex items-end gap-3 animate-pulse">
            <div className="w-10 h-10 rounded-2xl bg-blue-100 flex items-center justify-center text-blue-400 text-lg font-bold">ن</div>
            <div className="bg-blue-50 border border-blue-100 p-5 rounded-3xl rounded-tl-none flex items-center gap-3 shadow-sm">
              <div className="flex gap-1.5">
                <div className="w-2.5 h-2.5 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-2.5 h-2.5 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                <div className="w-2.5 h-2.5 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
              </div>
              <span className="text-sm text-blue-600 font-bold italic">نبراس ديفكر بسالفة...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Section */}
      <div className="p-4 md:p-6 bg-white border-t border-slate-200 shadow-[0_-8px_30px_rgb(0,0,0,0.04)]">
        <div className="max-w-5xl mx-auto flex gap-4 items-center">
          {/* Voice Mode Button */}
          <button 
            type="button"
            onClick={() => setIsLiveMode(true)}
            className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-blue-200 hover:scale-110 active:scale-90 transition-all flex-shrink-0 relative group"
            title="تحدث مع نبراس مباشرة"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
            <div className="absolute -top-14 left-1/2 -translate-x-1/2 bg-slate-900 text-white text-[11px] py-2 px-4 rounded-xl opacity-0 group-hover:opacity-100 transition-all transform scale-50 group-hover:scale-100 pointer-events-none whitespace-nowrap font-bold">
              سولف وية نبراس 🎙️
            </div>
          </button>

          <form onSubmit={handleSendMessage} className="flex-1 flex gap-3 relative">
            <div className="flex-1 relative group">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder={
                  activeMode === InteractionMode.TEACH_ME
                    ? "اشرح لي الي فهمته وهسة أصلحلك..."
                    : "اكتب سؤالك هسة..."
                }
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2rem] py-5 px-8 pr-16 focus:outline-none focus:border-blue-500 focus:bg-white transition-all shadow-inner text-lg placeholder:text-slate-400 font-medium"
                disabled={isLoading}
