import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { InteractionMode } from "../types";

const SYSTEM_INSTRUCTION = `
أنت "نبراس" (Nebras)، مدرس خصوصي عراقي ذكي، مرح، ومحبوب.
مهمتك مساعدة الطلاب في فهم المناهج من ملفات الـ PDF المرفقة أو الصور.

أنماط العمل:
1. Q&A: إجابات دقيقة ومختصرة.
2. Explain (شرح مبسط): استخدام "السوالف" العراقية والأمثلة اليومية لتقريب الفكرة.
3. Quiz: اختبار من 3-5 أسئلة MCQs.
4. Teach Me: الطالب يشرح وأنت تصحح له (Reverse Teaching).
5. Summary (التلخيص بـ 5 دقائق): لخص أهم 5 نقاط في الفصل كأنها "برشامة" قانونية ومفيدة.
6. Flashcards: حول المعلومات المهمة إلى صيغة: (السؤال: ... | الجواب: ...) ليسهل حفظها.
7. Image Analysis: إذا أرسل الطالب صورة لورقة حل، حلل خطواته، حدد الخطأ بدقة، وعلمه الصح بمودة.

الشخصية:
- استعمل لهجة عراقية بيضاء مفهومة ومحببة (مثل: "عاشت إيدك"، "يا بطل"، "لا تشيل هم"، "هسة تصفى").
- دائماً اربط المعلومات ببعضها (Cross-subject linking).
`;

export const getGeminiResponse = async (
  prompt: string,
  pdf: { base64: string; mimeType: string } | null,
  mode: InteractionMode,
  image?: { base64: string; mimeType: string }
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  let modeInstruction = "";
  switch (mode) {
    case InteractionMode.SUMMARY:
      modeInstruction = "سوي لي ملخص الـ 5 دقائق لهذا الجزء، أريد الزبدة بـ 5 نقاط بس.";
      break;
    case InteractionMode.FLASHCARDS:
      modeInstruction = "حول لي هاي المعلومات إلى بطاقات مراجعة (Flashcards) بصيغة سؤال وجواب.";
      break;
    case InteractionMode.EXPLAIN:
      modeInstruction = "احجي لي 'سالفة' عراقية تشبه هذا الموضوع حتى ما أنساه.";
      break;
    case InteractionMode.TEACH_ME:
      modeInstruction = "أنا راح أشرحلك، صلح لي فهمي بذكاء.";
      break;
    default:
      modeInstruction = "";
  }

  const parts: any[] = [{ text: prompt + "\n" + modeInstruction }];

  if (pdf) {
    parts.unshift({
      inlineData: { data: pdf.base64, mimeType: pdf.mimeType }
    });
  }

  if (image) {
    parts.push({
      inlineData: { data: image.base64, mimeType: image.mimeType }
    });
  }

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return result.text || "عذراً، صار خلل بسيط. جرب مرة ثانية.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "ما كدرت أتواصل وية خوادمي، تأكد من ملفاتك أو اتصالك.";
  }
};

export const getSpeechResponse = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `بلهجة عراقية محببة: ${text}` }] }],
      config: {
        responseModalities: ['AUDIO' as any],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    console.error("TTS Error", e);
    return undefined;
  }
};

