import { InteractionMode, ChatMessage, PDFData } from '../types';
import { getGeminiResponse, getSpeechResponse } from '../services/geminiService';
import { decode, decodeAudioData } from '../services/audioUtils';
import LiveModeOverlay from './LiveModeOverlay';

interface ChatInterfaceProps {
  currentPdf: PDFData | null;
  onPdfUpload: (pdf: PDFData) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentPdf, onPdfUpload }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeMode, setActiveMode] = useState<InteractionMode>(InteractionMode.QA);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [points, setPoints] = useState(0);
  const [pendingImage, setPendingImage] = useState<{ base64: string; mimeType: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    const savedPoints = localStorage.getItem('nebras_points');
    if (savedPoints) setPoints(parseInt(savedPoints));
  }, []);

  useEffect(() => {
    localStorage.setItem('nebras_points', points.toString());
  }, [points]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const playTTS = async (text: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const base64Audio = await getSpeechResponse(text);
    if (base64Audio) {
      const buffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.start();
    }
  };

  const handleSendMessage = async (e?: React.FormEvent, customPrompt?: string) => {
    e?.preventDefault();
    const finalInput = customPrompt || input;
    if (!finalInput.trim() && !pendingImage) return;

    const userMessage: ChatMessage = {
      role: 'user',
      content: finalInput || (pendingImage ? "حلل لي هذه الصورة" : ""),
      timestamp: new Date(),
      mode: activeMode
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const responseText = await getGeminiResponse(
      finalInput,
      currentPdf ? { base64: currentPdf.base64, mimeType: currentPdf.mimeType } : null,
      activeMode,
      pendingImage || undefined
    );

    const modelMessage: ChatMessage = {
      role: 'model',
      content: responseText,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, modelMessage]);
    setIsLoading(false);
    setPendingImage(null);
    setPoints(p => p + 10); // Reward student for interaction
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingImage({ base64, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const ModeBadge = ({ mode, label, icon }: { mode: InteractionMode; label: string; icon: string }) => (
    <button
      onClick={() => setActiveMode(mode)}
      className={`flex-shrink-0 flex items-center gap-2 px-5 py-3 rounded-2xl text-sm font-bold transition-all duration-300 border-2 ${
        activeMode === mode
          ? 'bg-blue-600 border-blue-600 text-white shadow-lg scale-105'
          : 'bg-white border-slate-100 text-slate-600 hover:border-blue-200'
      }`}
    >
      <span>{icon}</span>
      {label}
    </button>
  );

  return (
    <div className="flex flex-col flex-1 h-full bg-[#f8fafc] relative">
      {isLiveMode && (
        <LiveModeOverlay 
          currentPdf={currentPdf} 
          onClose={() => setIsLiveMode(false)}
          onTranscription={(t, r) => setMessages(prev => [...prev, { role: r, content: t, timestamp: new Date() }])}
        />
      )}

      {/* Header Info with Points */}
      <div className="bg-white/80 backdrop-blur-md border-b border-slate-200 p-4 sticky top-0 z-20 flex items-center justify-between shadow-sm">
        <div className="flex gap-2 overflow-x-auto no-scrollbar scroll-smooth flex-1 max-w-[80%]">
          <ModeBadge mode={InteractionMode.QA} label="سؤال" icon="❓" />
          <ModeBadge mode={InteractionMode.EXPLAIN} label="سالفة" icon="💡" />
          <ModeBadge mode={InteractionMode.SUMMARY} label="الخلاصة" icon="⏳" />
          <ModeBadge mode={InteractionMode.FLASHCARDS} label="بطاقات" icon="🗂️" />
          <ModeBadge mode={InteractionMode.QUIZ} label="اختبرني" icon="📝" />
        </div>
        <div className="bg-amber-100 text-amber-700 px-4 py-2 rounded-2xl font-black text-sm flex items-center gap-2 border border-amber-200 shadow-sm animate-bounce-slow">
            <span>🏆</span>
            {points} نقطة
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-8 custom-scrollbar">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex items-end gap-3 ${msg.role === 'user' ? 'flex-row-reverse justify-start' : 'flex-row justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
            <div className={`w-10 h-10 rounded-2xl flex-shrink-0 flex items-center justify-center shadow-md font-bold ${msg.role === 'user' ? 'bg-slate-800 text-white' : 'bg-blue-600 text-white'}`}>
                {msg.role === 'user' ? 'أ' : 'ن'}
            </div>
            <div className={`flex flex-col max-w-[85%] md:max-w-[70%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`p-5 rounded-3xl shadow-sm border ${msg.role === 'user' ? 'bg-white border-slate-200 text-slate-800 rounded-tr-none' : 'bg-gradient-to-br from-blue-600 to-blue-700 border-blue-500 text-white rounded-tl-none shadow-lg'}`}>
                    <div className="whitespace-pre-wrap text-[16px] leading-relaxed font-medium">
                        {msg.content}
                    </div>
                    {msg.role === 'model' && (
                      <button onClick={() => playTTS(msg.content)} className="mt-3 flex items-center gap-2 text-[11px] bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-full transition-all">
                        <span>🔊</span> اسمع السالفة
                      </button>
                    )}
                </div>
                <div className="mt-1 flex items-center gap-2 px-1">
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{msg.role === 'user' ? 'أنت' : 'نبراس'}</span>
                </div>
            </div>
          </div>
        ))}
        {isLoading && <div className="animate-pulse flex items-center gap-2 text-blue-500 font-bold italic text-sm">نبراس جاي يحضر لك الزبدة... ✨</div>}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Form */}
      <div className="p-4 md:p-6 bg-white border-t border-slate-200">
        <div className="max-w-5xl mx-auto flex gap-4 items-center">
          <button type="button" onClick={() => setIsLiveMode(true)} className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg hover:scale-105 transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
          </button>

          <form onSubmit={handleSendMessage} className="flex-1 flex gap-3">
            <div className="flex-1 relative">
              <input
                type="text" value={input} onChange={(e) => setInput(e.target.value)}
                placeholder={activeMode === InteractionMode.SUMMARY ? "اضغط إرسال لتلخيص المادة هسة..." : "اكتب سؤالك أو اشرح فهمك..."}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl py-4.5 px-6 pr-16 focus:outline-none focus:border-blue-500 focus:bg-white transition-all shadow-inner font-medium"
              />
              <label className="absolute left-4 top-1/2 -translate-y-1/2 cursor-pointer hover:bg-slate-200 p-2 rounded-xl transition-all text-slate-400">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </label>
              {pendingImage && <div className="absolute -top-12 right-0 bg-blue-100 text-blue-600 px-3 py-1 rounded-lg text-xs font-bold border border-blue-200 animate-bounce">تم اختيار صورة للتحليل 📸</div>}
            </div>
            <button type="submit" disabled={isLoading} className="bg-blue-600 text-white px-8 py-4 rounded-3xl font-black shadow-lg hover:bg-blue-700 disabled:bg-slate-200 transition-all">إرسال</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

