export enum InteractionMode {
  QA = 'QA',
  EXPLAIN = 'EXPLAIN',
  QUIZ = 'QUIZ',
  TEACH_ME = 'TEACH_ME',
  SUMMARY = 'SUMMARY',
  FLASHCARDS = 'FLASHCARDS',
  CORRECT_MY_WORK = 'CORRECT_MY_WORK',
  VISUALIZE = 'VISUALIZE'
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
  mode?: InteractionMode;
  imageUrl?: string;
  generatedImageUrl?: string;
}

export interface PDFData {
  name: string;
  base64: string;
  mimeType: string;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { InteractionMode } from "../types";

const SYSTEM_INSTRUCTION = `
أنت "نبراس" (Nebras)، مدرس خصوصي عراقي ذكي، مرح، ومحبوب.
مهمتك مساعدة الطلاب في فهم المناهج من ملفات الـ PDF المرفقة أو الصور.

أنماط العمل المتقدمة:
1. Q&A: إجابات دقيقة ومختصرة.
2. Explain (ميزة السالفة): حول التعريف العلمي الجاف إلى قصة عراقية قصيرة مستوحاة من حياتنا اليومية.
3. Summary (الخلاصة بـ 5 دقائق): لخص المادة بـ 5 نقاط أساسية أو خريطة مفاهيم نصية.
4. Flashcards: استخرج أهم المعلومات ونسقها كـ (سؤال: ... | جواب: ...).
5. Correct My Work: إذا الطالب أرسل صورة لحله، حلل الصورة، حدد الخطأ بالخطوة، وعلمه الصح.
6. Visualize: صف المفهوم العلمي بدقة لغرض تخيله أو توليد صورة له.
7. Teach Me: الطالب يشرح وأنت تقيمه.

الشخصية واللغة:
- استخدم لهجة عراقية محببة (عاشت إيدك، يا بطل، تدلل، هسة تصفى).
- دائماً اذكر رقم الصفحة أو الفصل إذا كان الملف مرفقاً.
- اربط بين المواد (مثلاً ربط معلومة في الفيزياء بمعلومة سابقة في الكيمياء).
`;

export const getGeminiResponse = async (
  prompt: string,
  pdf: { base64: string; mimeType: string } | null,
  mode: InteractionMode,
  image?: { base64: string; mimeType: string }
): Promise<{ text: string; generatedImage?: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  // Handling Image Generation specifically
  if (mode === InteractionMode.VISUALIZE) {
    const imgResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: [{ parts: [{ text: `صورة تعليمية توضيحية لـ: ${prompt}. اجعلها واضحة ومناسبة للطلاب.` }] }]
    });

    let base64Img = "";
    for (const part of imgResponse.candidates[0].content.parts) {
      if (part.inlineData) base64Img = `data:image/png;base64,${part.inlineData.data}`;
    }

    return { 
      text: "عاشت إيدك، هاي صورة توضح المفهوم اللي سألت عنه. شوفها بتركيز!",
      generatedImage: base64Img 
    };
  }

  let modeInstruction = "";
  switch (mode) {
    case InteractionMode.SUMMARY:
      modeInstruction = "أريد 'خلاصة الـ 5 دقائق' لهذا الجزء، لخصه بـ 5 نقاط ذهبية.";
      break;
    case InteractionMode.FLASHCARDS:
      modeInstruction = "حول لي هاي المادة إلى بطاقات مراجعة (سؤال وجواب) حتى أحفظها بسرعة.";
      break;
    case InteractionMode.CORRECT_MY_WORK:
      modeInstruction = "شوف حلي بالصورة، وين خطأي؟ وشلون أصححه؟";
      break;
    default:
      modeInstruction = "";
  }

  const parts: any[] = [{ text: prompt + "\n" + modeInstruction }];

  if (pdf) {
    parts.unshift({ inlineData: { data: pdf.base64, mimeType: pdf.mimeType } });
  }

  if (image) {
    parts.push({ inlineData: { data: image.base64, mimeType: image.mimeType } });
  }

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [{ role: 'user', parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return { text: result.text || "عذراً، صار خلل بسيط." };
  } catch (error) {
    console.error("Gemini API Error:", error);
    return { text: "ما كدرت أتواصل وية خوادمي." };
  }
};

export const getSpeechResponse = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `بصوت مدرس عراقي حنون ومحفز: ${text}` }] }],
      config: {
        responseModalities: ['AUDIO' as any],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    return undefined;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { InteractionMode, ChatMessage, PDFData } from '../types';
import { getGeminiResponse, getSpeechResponse } from '../services/geminiService';
import { decode, decodeAudioData } from '../services/audioUtils';
import LiveModeOverlay from './LiveModeOverlay';

interface ChatInterfaceProps {
  currentPdf: PDFData | null;
  onPdfUpload: (pdf: PDFData) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentPdf, onPdfUpload }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeMode, setActiveMode] = useState<InteractionMode>(InteractionMode.QA);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [points, setPoints] = useState(0);
  const [pendingImage, setPendingImage] = useState<{ base64: string; mimeType: string; preview: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    const savedPoints = localStorage.getItem('nebras_points');
    if (savedPoints) setPoints(parseInt(savedPoints));
  }, []);

  useEffect(() => {
    localStorage.setItem('nebras_points', points.toString());
  }, [points]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const playTTS = async (text: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const base64Audio = await getSpeechResponse(text);
    if (base64Audio) {
      const buffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.start();
    }
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() && !pendingImage) return;

    const userMsg: ChatMessage = {
      role: 'user',
      content: input,
      timestamp: new Date(),
      mode: activeMode,
      imageUrl: pendingImage?.preview
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const response = await getGeminiResponse(
      input,
      currentPdf ? { base64: currentPdf.base64, mimeType: currentPdf.mimeType } : null,
      activeMode,
      pendingImage ? { base64: pendingImage.base64, mimeType: pendingImage.mimeType } : undefined
    );

    const modelMsg: ChatMessage = {
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      generatedImageUrl: response.generatedImage
    };

    setMessages(prev => [...prev, modelMsg]);
    setIsLoading(false);
    setPendingImage(null);
    setPoints(p => p + 15); // Reward interaction
    scrollToBottom();
  };

  const handleCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingImage({ 
          base64, 
          mimeType: file.type, 
          preview: event.target?.result as string 
        });
        setActiveMode(InteractionMode.CORRECT_MY_WORK);
      };
      reader.readAsDataURL(file);
    }
  };

  const ModeButton = ({ mode, label, icon }: { mode: InteractionMode; label: string; icon: string }) => (
    <button
      onClick={() => setActiveMode(mode)}
      className={`flex-shrink-0 flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all border-2 ${
        activeMode === mode
          ? 'bg-blue-600 border-blue-600 text-white shadow-md scale-105'
          : 'bg-white border-slate-100 text-slate-500 hover:border-blue-200 hover:text-blue-600'
      }`}
    >
      <span>{icon}</span> {label}
    </button>
  );

  return (
    <div className="flex flex-col flex-1 h-full bg-[#f8fafc] relative">
      {isLiveMode && (
        <LiveModeOverlay 
          currentPdf={currentPdf} 
          onClose={() => setIsLiveMode(false)}
          onTranscription={(t, r) => setMessages(prev => [...prev, { role: r, content: t, timestamp: new Date() }])}
        />
      )}

      {/* Dynamic Header */}
      <div className="bg-white/80 backdrop-blur-md border-b border-slate-200 p-3 sticky top-0 z-20 flex items-center justify-between shadow-sm overflow-x-auto no-scrollbar">
        <div className="flex gap-2">
          <ModeButton mode={InteractionMode.QA} label="أسأل" icon="❓" />
          <ModeButton mode={InteractionMode.EXPLAIN} label="سالفة" icon="🗣️" />
          <ModeButton mode={InteractionMode.SUMMARY} label="الخلاصة" icon="⏳" />
          <ModeButton mode={InteractionMode.FLASHCARDS} label="بطاقات" icon="🗂️" />
          <ModeButton mode={InteractionMode.VISUALIZE} label="تخيل" icon="🎨" />
          <ModeButton mode={InteractionMode.CORRECT_MY_WORK} label="صحح لي" icon="📸" />
        </div>
        <div className="hidden md:flex bg-amber-50 text-amber-600 px-4 py-1.5 rounded-full font-black text-xs items-center gap-2 border border-amber-100 shadow-sm ml-4">
            <span className="text-lg">💎</span> {points} نقطة نبراس
        </div>
      </div>

      {/* Message List */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center p-10 opacity-60 animate-in fade-in duration-1000">
             <div className="w-24 h-24 bg-blue-100 rounded-full flex items-center justify-center text-5xl mb-4">📚</div>
             <h3 className="text-xl font-bold text-slate-800">أهلاً بك في عالم نبراس!</h3>
             <p className="text-slate-500 max-w-xs mt-2">ارفع كتابك، صور حلك، أو بس اسأل سؤلك واني موجود أساعدك.</p>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div key={idx} className={`flex items-end gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'} animate-in slide-in-from-bottom-4 duration-300`}>
            <div className={`w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center font-bold text-sm ${msg.role === 'user' ? 'bg-slate-700 text-white' : 'bg-blue-600 text-white shadow-lg'}`}>
              {msg.role === 'user' ? 'أ' : 'ن'}
            </div>
            <div className={`flex flex-col max-w-[80%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`p-4 rounded-2xl shadow-sm border ${msg.role === 'user' ? 'bg-white border-slate-200 text-slate-800 rounded-tr-none' : 'bg-gradient-to-br from-blue-600 to-blue-700 border-blue-500 text-white rounded-tl-none'}`}>
                {msg.imageUrl && <img src={msg.imageUrl} className="w-full max-w-sm rounded-lg mb-3 border border-slate-100 shadow-inner" alt="User upload" />}
                {msg.generatedImageUrl && <img src={msg.generatedImageUrl} className="w-full max-w-sm rounded-lg mb-3 border-4 border-white shadow-lg" alt="Nebras visual" />}
                <div className="whitespace-pre-wrap leading-relaxed font-medium">{msg.content}</div>
                {msg.role === 'model' && (
                  <button onClick={() => playTTS(msg.content)} className="mt-3 flex items-center gap-1.5 text-[10px] bg-white/20 hover:bg-white/30 px-3 py-1 rounded-full transition-all font-bold">
                    <span>🔊</span> اسمع الشرح
                  </button>
                )}
              </div>
              <span className="text-[10px] text-slate-400 mt-1 px-1 font-bold">{msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
            </div>
          </div>
        ))}
        {isLoading && <div className="text-blue-500 text-sm font-bold animate-pulse px-12">نبراس جاي يسويلك الزبدة... ✨</div>}
        <div ref={messagesEndRef} />
      </div>

      {/* Combined Input Bar */}
      <div className="p-4 bg-white border-t border-slate-100 shadow-[0_-10px_30px_rgba(0,0,0,0.03)]">
        {pendingImage && (
          <div className="mb-3 p-2 bg-blue-50 border border-blue-100 rounded-xl flex items-center justify-between animate-in slide-in-from-bottom-2">
            <div className="flex items-center gap-3">
               <img src={pendingImage.preview} className="w-12 h-12 object-cover rounded-lg border border-blue-200" alt="Thumbnail" />
               <span className="text-xs font-bold text-blue-700">تم تجهيز الصورة للتحليل 📸</span>
            </div>
            <button onClick={() => setPendingImage(null)} className="text-red-500 hover:bg-red-50 p-2 rounded-full transition-all">✕</button>
          </div>
        )}

        <div className="max-w-5xl mx-auto flex gap-3 items-center">
          <button type="button" onClick={() => setIsLiveMode(true)} className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg hover:rotate-12 transition-all flex-shrink-0">🎙️</button>

          <form onSubmit={handleSendMessage} className="flex-1 flex gap-2">
            <div className="flex-1 relative group">
              <input
                type="text" value={input} onChange={(e) => setInput(e.target.value)}
                placeholder={activeMode === InteractionMode.CORRECT_MY_WORK ? "احجيلي شصار وياك بهاي المسألة؟" : "اسأل نبراس أي شي..."}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-3.5 px-5 pr-12 focus:outline-none focus:border-blue-500 focus:bg-white transition-all shadow-inner font-medium"
              />
              <label className="absolute left-3 top-1/2 -translate-y-1/2 cursor-pointer hover:bg-slate-200 p-2 rounded-xl transition-all text-slate-400 hover:text-blue-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                <input type="file" className="hidden" accept="image/*" onChange={handleCapture} />
              </label>
            </div>
            <button type="submit" disabled={isLoading} className="bg-blue-600 text-white px-6 py-3.5 rounded-2xl font-black shadow-lg hover:bg-blue-700 disabled:bg-slate-200 transition-all flex items-center gap-2">
               <span>إرسال</span>
               <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 rotate-180" viewBox="0 0 20 20" fill="currentColor"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useRef, useEffect } from 'react';
import { InteractionMode, ChatMessage, PDFData } from '../types';
import { getGeminiResponse, getSpeechResponse } from '../services/geminiService';
import { decode, decodeAudioData } from '../services/audioUtils';
import LiveModeOverlay from './LiveModeOverlay';

interface ChatInterfaceProps {
  currentPdf: PDFData | null;
  onPdfUpload: (pdf: PDFData) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ currentPdf, onPdfUpload }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeMode, setActiveMode] = useState<InteractionMode>(InteractionMode.QA);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [points, setPoints] = useState(0);
  const [pendingImage, setPendingImage] = useState<{ base64: string; mimeType: string; preview: string } | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedPoints = localStorage.getItem('nebras_points');
    if (savedPoints) setPoints(parseInt(savedPoints));

    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    localStorage.setItem('nebras_points', points.toString());
    scrollToBottom();
  }, [messages, points]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const playTTS = async (text: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const base64Audio = await getSpeechResponse(text);
    if (base64Audio) {
      const buffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.start();
    }
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() && !pendingImage) return;

    const userMsg: ChatMessage = {
      role: 'user',
      content: input,
      timestamp: new Date(),
      mode: activeMode,
      imageUrl: pendingImage?.preview
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    setIsMenuOpen(false);

    const response = await getGeminiResponse(
      input,
      currentPdf ? { base64: currentPdf.base64, mimeType: currentPdf.mimeType } : null,
      activeMode,
      pendingImage ? { base64: pendingImage.base64, mimeType: pendingImage.mimeType } : undefined
    );

    const modelMsg: ChatMessage = {
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      generatedImageUrl: response.generatedImage
    };

    setMessages(prev => [...prev, modelMsg]);
    setIsLoading(false);
    setPendingImage(null);
    setPoints(p => p + 15);
    setActiveMode(InteractionMode.QA); // Reset mode after sending
  };

  const handlePdfUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        onPdfUpload({ name: file.name, base64, mimeType: file.type });
        setIsMenuOpen(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleImageCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingImage({ 
          base64, 
          mimeType: file.type, 
          preview: event.target?.result as string 
        });
        setActiveMode(InteractionMode.CORRECT_MY_WORK);
        setIsMenuOpen(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const selectMode = (mode: InteractionMode) => {
    setActiveMode(mode);
    setIsMenuOpen(false);
    // If it's a direct action like summary or quiz without input, we might want to trigger something
    if (mode === InteractionMode.SUMMARY) setInput("لخص لي المادة الحالية بـ 5 دقائق");
    if (mode === InteractionMode.QUIZ) setInput("اختبرني بالمادة الحالية");
  };

  return (
    <div className="flex flex-col flex-1 h-full bg-[#f8fafc] relative">
      {isLiveMode && (
        <LiveModeOverlay 
          currentPdf={currentPdf} 
          onClose={() => setIsLiveMode(false)}
          onTranscription={(t, r) => setMessages(prev => [...prev, { role: r, content: t, timestamp: new Date() }])}
        />
      )}

      {/* Top Bar - Minimal */}
      <div className="bg-white/80 backdrop-blur-md border-b border-slate-200 p-4 sticky top-0 z-20 flex items-center justify-between">
        <div className="flex items-center gap-2">
           <span className="text-xs font-black text-slate-400 uppercase tracking-tighter">الجلسة الحالية:</span>
           <span className="text-xs font-bold text-blue-600 truncate max-w-[150px]">
             {currentPdf ? currentPdf.name : 'لا يوجد كتاب مرفوع'}
           </span>
        </div>
        <div className="bg-amber-100 text-amber-700 px-3 py-1 rounded-full font-black text-[10px] border border-amber-200 flex items-center gap-1">
            <span>💎</span> {points}
        </div>
      </div>

      {/* Chat Messages */}
      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-sm mx-auto opacity-80">
             <div className="w-20 h-20 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-3xl flex items-center justify-center text-white text-4xl shadow-2xl mb-6 animate-bounce-slow">ن</div>
             <h2 className="text-2xl font-black text-slate-800 mb-2">أهلاً بطل! شنو نقرأ اليوم؟</h2>
             <p className="text-slate-500 text-sm leading-relaxed">أني نبراس، مدرسك الخصوصي. تكدر ترفع ملزمتك، تسألني أي سؤال، أو حتى تصور حلك وأصححه إلك.</p>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div key={idx} className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`w-10 h-10 rounded-2xl flex-shrink-0 flex items-center justify-center font-bold text-sm shadow-sm ${msg.role === 'user' ? 'bg-slate-800 text-white' : 'bg-blue-600 text-white'}`}>
              {msg.role === 'user' ? 'أ' : 'ن'}
            </div>
            <div className={`flex flex-col max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`p-5 rounded-3xl shadow-sm border text-[16px] leading-relaxed ${msg.role === 'user' ? 'bg-white border-slate-200 text-slate-800 rounded-tr-none' : 'bg-blue-50 border-blue-100 text-slate-800 rounded-tl-none'}`}>
                {msg.imageUrl && <img src={msg.imageUrl} className="w-full max-w-sm rounded-2xl mb-4 border border-slate-200" alt="Capture" />}
                {msg.generatedImageUrl && <img src={msg.generatedImageUrl} className="w-full max-w-sm rounded-2xl mb-4 border-4 border-white shadow-xl" alt="Visual" />}
                <div className="whitespace-pre-wrap font-medium">{msg.content}</div>
                {msg.role === 'model' && (
                  <button onClick={() => playTTS(msg.content)} className="mt-4 flex items-center gap-2 text-[11px] bg-blue-100 text-blue-700 hover:bg-blue-200 px-4 py-2 rounded-full transition-all font-bold">
                    <span>🔊</span> اسمع الشرح
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-3 text-blue-500 font-black italic text-xs animate-pulse px-14">
             <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></span>
             نبراس جاي يحضر لك الزبدة...
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Modern Input Bar with Popup Menu */}
      <div className="p-4 md:p-6 bg-white border-t border-slate-100 relative">
        <div className="max-w-4xl mx-auto flex items-end gap-3">

          {/* Action Menu Trigger */}
          <div className="relative" ref={menuRef}>
            <button 
              type="button"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-lg ${isMenuOpen ? 'bg-slate-800 text-white rotate-45' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
            </button>

            {/* Popup Menu */}
            {isMenuOpen && (
              <div className="absolute bottom-16 right-0 w-64 bg-white rounded-3xl shadow-2xl border border-slate-100 p-3 animate-in slide-in-from-bottom-4 duration-200 z-50">
                <div className="space-y-1">
                  <label className="flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-blue-50 text-slate-700 cursor-pointer transition-all group">
                    <span className="text-xl">📁</span>
                    <div className="flex flex-col">
                      <span className="text-sm font-bold group-hover:text-blue-600">رفع كتاب/ملزمة</span>
                      <span className="text-[10px] text-slate-400">PDF فقط</span>
                    </div>
                    <input type="file" className="hidden" accept="application/pdf" onChange={handlePdfUpload} />
                  </label>

                  <div className="h-px bg-slate-50 my-2"></div>

                  <MenuOption icon="💡" title="سالفة عراقية" desc="شرح ممتع وقريب للقلب" onClick={() => selectMode(InteractionMode.EXPLAIN)} />
                  <MenuOption icon="⏳" title="خلاصة الـ 5 دقائق" desc="أهم النقاط بالفصل" onClick={() => selectMode(InteractionMode.SUMMARY)} />
                  <MenuOption icon="🗂️" title="بطاقات مراجعة" desc="سؤال وجواب للحفظ" onClick={() => selectMode(InteractionMode.FLASHCARDS)} />
                  <MenuOption icon="🎨" title="تخيل المفهوم" desc="توليد صورة توضيحية" onClick={() => selectMode(InteractionMode.VISUALIZE)} />
                  <label className="flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-amber-50 text-slate-700 cursor-pointer transition-all group">
                    <span className="text-xl">📸</span>
                    <div className="flex flex-col">
                      <span className="text-sm font-bold group-hover:text-amber-600">صحح حلي</span>
                      <span className="text-[10px] text-slate-400">صور دفترك ونصلحه</span>
                    </div>
                    <input type="file" className="hidden" accept="image/*" onChange={handleImageCapture} />
                  </label>
                </div>
              </div>
            )}
          </div>

          {/* Main Input Field */}
          <form onSubmit={handleSendMessage} className="flex-1 flex flex-col gap-2">
            {pendingImage && (
              <div className="flex items-center gap-2 bg-blue-50 p-2 rounded-2xl border border-blue-100 self-start animate-in fade-in">
                <img src={pendingImage.preview} className="w-8 h-8 rounded-lg object-cover" alt="Preview" />
                <span className="text-[10px] font-bold text-blue-600">تم تجهيز الصورة للتحليل</span>
                <button type="button" onClick={() => setPendingImage(null)} className="text-blue-400 hover:text-red-500">✕</button>
              </div>
            )}
            <div className="relative group">
              <textarea
                rows={1}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); } }}
                placeholder={activeMode !== InteractionMode.QA ? `تم تفعيل وضع: ${activeMode}...` : "اسأل نبراس عن أي شي ببالك..."}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl py-4 px-6 pr-14 focus:outline-none focus:border-blue-500 focus:bg-white transition-all shadow-inner font-medium resize-none min-h-[56px] max-h-32 custom-scrollbar"
              />
              <button 
                type="button" 
                onClick={() => setIsLiveMode(true)}
                className="absolute left-3 top-1/2 -translate-y-1/2 w-10 h-10 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              </button>
            </div>
          </form>

          <button 
            onClick={handleSendMessage}
            disabled={isLoading || (!input.trim() && !pendingImage)}
            className="w-12 h-12 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg hover:bg-blue-700 disabled:bg-slate-200 disabled:shadow-none transition-all flex-shrink-0"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 rotate-180" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

const MenuOption = ({ icon, title, desc, onClick }: { icon: string; title: string; desc: string; onClick: () => void }) => (
  <button onClick={onClick} className="w-full flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-slate-50 text-right transition-all group">
    <span className="text-xl group-hover:scale-110 transition-transform">{icon}</span>
    <div className="flex flex-col">
      <span className="text-sm font-bold text-slate-700">{title}</span>
      <span className="text-[10px] text-slate-400">{desc}</span>
    </div>
  </button>
);

export default ChatInterface;

