export enum InteractionMode {
  QA = 'QA',
  EXPLAIN = 'EXPLAIN',
  QUIZ = 'QUIZ',
  TEACH_ME = 'TEACH_ME',
  SUMMARY = 'SUMMARY',
  FLASHCARDS = 'FLASHCARDS',
  CORRECT_MY_WORK = 'CORRECT_MY_WORK',
  VISUALIZE = 'VISUALIZE'
}

export interface User {
  username: string;
  points: number;
  joinedAt: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
  mode?: InteractionMode;
  imageUrl?: string;
  generatedImageUrl?: string;
}

export interface PDFData {
  name: string;
  base64: string;
  mimeType: string;
}

export interface ChatHistoryEntry {
  id: string;
  title: string;
  pdf: PDFData | null;
  messages: ChatMessage[];
  timestamp: string;
}

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import Auth from './components/Auth';
import { PDFData, User, ChatHistoryEntry, ChatMessage } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // History management
  const [allChats, setAllChats] = useState<ChatHistoryEntry[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  useEffect(() => {
    // Check for active session
    const savedUser = localStorage.getItem('nebras_active_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }

    // Load all chats from history
    const savedChats = localStorage.getItem('nebras_chat_history');
    if (savedChats) {
      const parsed = JSON.parse(savedChats).map((chat: any) => ({
        ...chat,
        messages: chat.messages.map((m: any) => ({ ...m, timestamp: new Date(m.timestamp) }))
      }));
      setAllChats(parsed);

      // Load last active chat if exists
      const lastId = localStorage.getItem('nebras_active_chat_id');
      if (lastId && parsed.find((c: any) => c.id === lastId)) {
        setActiveChatId(lastId);
      } else if (parsed.length > 0) {
        setActiveChatId(parsed[0].id);
      } else {
        createNewChat();
      }
    } else {
      createNewChat();
    }

    setIsAuthLoading(false);
  }, []);

  // Save history whenever it changes
  useEffect(() => {
    if (allChats.length > 0) {
      localStorage.setItem('nebras_chat_history', JSON.stringify(allChats));
    }
  }, [allChats]);

  // Save active chat ID
  useEffect(() => {
    if (activeChatId) {
      localStorage.setItem('nebras_active_chat_id', activeChatId);
    }
  }, [activeChatId]);

  const createNewChat = () => {
    const newId = Date.now().toString();
    const newChat: ChatHistoryEntry = {
      id: newId,
      title: 'محادثة جديدة',
      pdf: null,
      messages: [],
      timestamp: new Date().toISOString()
    };
    setAllChats(prev => [newChat, ...prev]);
    setActiveChatId(newId);
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('nebras_active_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (window.confirm('هل تريد تسجيل الخروج؟')) {
      setCurrentUser(null);
      localStorage.removeItem('nebras_active_user');
      localStorage.removeItem('nebras_active_chat_id');
      window.location.reload();
    }
  };

  const handleUpdateMessages = (chatId: string, messages: ChatMessage[]) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        // Update title based on first message if it's still default
        let title = chat.title;
        if (title === 'محادثة جديدة' && messages.length > 0) {
          title = messages[0].content.slice(0, 30) + (messages[0].content.length > 30 ? '...' : '');
        }
        return { ...chat, messages, title, timestamp: new Date().toISOString() };
      }
      return chat;
    }));
  };

  const handleUpdatePdf = (chatId: string, pdf: PDFData) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        return { ...chat, pdf, title: pdf.name };
      }
      return chat;
    }));
  };

  const handleClearPdf = (chatId: string) => {
    if (window.confirm('هل أنت متأكد من إغلاق هذا الملف؟')) {
      setAllChats(prev => prev.map(chat => {
        if (chat.id === chatId) {
          return { ...chat, pdf: null };
        }
        return chat;
      }));
    }
  };

  const handleDeleteChat = (chatId: string) => {
    if (window.confirm('هل تريد حذف هذه المحادثة؟')) {
      const filtered = allChats.filter(c => c.id !== chatId);
      setAllChats(filtered);
      if (activeChatId === chatId) {
        if (filtered.length > 0) {
          setActiveChatId(filtered[0].id);
        } else {
          createNewChat();
        }
      }
    }
  };

  if (isAuthLoading) return <div className="min-h-screen bg-slate-900 flex items-center justify-center text-white font-black animate-pulse">جاري التحميل...</div>;

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  const activeChat = allChats.find(c => c.id === activeChatId) || allChats[0];

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      <div className="flex w-full h-[calc(100vh-64px)] overflow-hidden">
        <Sidebar 
          currentPdf={activeChat?.pdf || null} 
          onClear={() => handleClearPdf(activeChatId!)}
          history={allChats}
          activeChatId={activeChatId}
          onSelectChat={setActiveChatId}
          onNewChat={createNewChat}
          onDeleteChat={handleDeleteChat}
        />
        {activeChat && (
          <ChatInterface 
            key={activeChat.id}
            initialMessages={activeChat.messages}
            currentPdf={activeChat.pdf} 
            onPdfUpload={(pdf) => handleUpdatePdf(activeChat.id, pdf)} 
            currentUser={currentUser}
            onMessagesChange={(msgs) => handleUpdateMessages(activeChat.id, msgs)}
            onPointsUpdate={(newPoints) => {
              const updated = { ...currentUser, points: newPoints };
              setCurrentUser(updated);
              localStorage.setItem('nebras_active_user', JSON.stringify(updated));

              const users = JSON.parse(localStorage.getItem('nebras_users') || '[]');
              const idx = users.findIndex((u: any) => u.username === currentUser.username);
              if (idx !== -1) {
                users[idx].points = newPoints;
                localStorage.setItem('nebras_users', JSON.stringify(users));
              }
            }}
          />
        )}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { InteractionMode, ChatMessage, PDFData, User } from '../types';
import { getGeminiResponse } from '../services/geminiService';
import LiveModeOverlay from './LiveModeOverlay';

interface ChatInterfaceProps {
  initialMessages: ChatMessage[];
  currentPdf: PDFData | null;
  onPdfUpload: (pdf: PDFData) => void;
  currentUser: User;
  onPointsUpdate: (points: number) => void;
  onMessagesChange: (messages: ChatMessage[]) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  initialMessages, 
  currentPdf, 
  onPdfUpload, 
  currentUser, 
  onPointsUpdate,
  onMessagesChange
}) => {
  const [messages, setMessages] = useState<ChatMessage[]>(initialMessages);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeMode, setActiveMode] = useState<InteractionMode>(InteractionMode.QA);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [pendingImage, setPendingImage] = useState<{ base64: string; mimeType: string; preview: string } | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    scrollToBottom();
    onMessagesChange(messages);
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() && !pendingImage) return;

    const userMsg: ChatMessage = {
      role: 'user',
      content: input,
      timestamp: new Date(),
      mode: activeMode,
      imageUrl: pendingImage?.preview
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    setIsMenuOpen(false);

    const response = await getGeminiResponse(
      input,
      currentPdf ? { base64: currentPdf.base64, mimeType: currentPdf.mimeType } : null,
      activeMode,
      pendingImage ? { base64: pendingImage.base64, mimeType: pendingImage.mimeType } : undefined
    );

    const modelMsg: ChatMessage = {
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      generatedImageUrl: response.generatedImage
    };

    setMessages(prev => [...prev, modelMsg]);
    setIsLoading(false);
    setPendingImage(null);
    onPointsUpdate(currentUser.points + 15);
    setActiveMode(InteractionMode.QA);
  };

  const handlePdfUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        onPdfUpload({ name: file.name, base64, mimeType: file.type });
        setIsMenuOpen(false);
        onPointsUpdate(currentUser.points + 50);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleImageCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingImage({ 
          base64, 
          mimeType: file.type, 
          preview: event.target?.result as string 
        });
        setActiveMode(InteractionMode.CORRECT_MY_WORK);
        setIsMenuOpen(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const selectMode = (mode: InteractionMode) => {
    setActiveMode(mode);
    setIsMenuOpen(false);
    if (mode === InteractionMode.SUMMARY) setInput("لخص لي المادة الحالية بـ 5 دقائق");
    if (mode === InteractionMode.QUIZ) setInput("اختبرني بالمادة الحالية");
  };

  return (
    <div className="flex flex-col flex-1 h-full bg-[#f8fafc] relative">
      {isLiveMode && (
        <LiveModeOverlay 
          currentPdf={currentPdf} 
          onClose={() => setIsLiveMode(false)}
          onTranscription={(t, r) => setMessages(prev => [...prev, { role: r, content: t, timestamp: new Date() }])}
        />
      )}

      {/* Top Bar */}
      <div className="bg-white/80 backdrop-blur-md border-b border-slate-200 p-4 sticky top-0 z-20 flex items-center justify-between">
        <div className="flex items-center gap-2">
           <span className="text-xs font-black text-slate-400 uppercase tracking-tighter">الجلسة:</span>
           <span className="text-xs font-bold text-blue-600 truncate max-w-[150px]">
             {currentPdf ? currentPdf.name : 'لا يوجد ملف'}
           </span>
        </div>
        <div className="flex items-center gap-2">
          <div className="bg-amber-100 text-amber-700 px-3 py-1.5 rounded-2xl font-black text-xs border border-amber-200 flex items-center gap-2">
              <span className="animate-pulse">💎</span> {currentUser.points} نقطة
          </div>
        </div>
      </div>

      {/* Chat Messages */}
      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center max-w-sm mx-auto opacity-80">
             <div className="w-24 h-24 bg-blue-600 rounded-[2rem] flex items-center justify-center text-white text-5xl shadow-2xl mb-8 animate-bounce-slow">ن</div>
             <h2 className="text-2xl font-black text-slate-800 mb-2">هلا بيك {currentUser.username}!</h2>
             <p className="text-slate-500 text-sm leading-relaxed">أني نبراس، جاهز أساعدك اليوم. ارفع ملزمتك من علامة (+) أو اسألني أي شي ببالك.</p>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div key={idx} className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`w-11 h-11 rounded-2xl flex-shrink-0 flex items-center justify-center font-bold text-lg shadow-md ${msg.role === 'user' ? 'bg-slate-800 text-white' : 'bg-blue-600 text-white'}`}>
              {msg.role === 'user' ? currentUser.username[0] : 'ن'}
            </div>
            <div className={`flex flex-col max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`p-5 rounded-3xl shadow-sm border text-[16px] leading-relaxed ${msg.role === 'user' ? 'bg-white border-slate-200 text-slate-800 rounded-tr-none' : 'bg-blue-50 border-blue-100 text-slate-800 rounded-tl-none'}`}>
                {msg.imageUrl && <img src={msg.imageUrl} className="w-full max-w-sm rounded-2xl mb-4 border border-slate-200" alt="Capture" />}
                {msg.generatedImageUrl && <img src={msg.generatedImageUrl} className="w-full max-w-sm rounded-2xl mb-4 border-4 border-white shadow-xl" alt="Visual" />}
                <div className="whitespace-pre-wrap font-medium">{msg.content}</div>
              </div>
              <span className="text-[10px] text-slate-400 mt-2 font-bold uppercase tracking-widest">{msg.role === 'model' ? 'نبراس' : currentUser.username} • {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-3 text-blue-500 font-black italic text-xs animate-pulse px-16">
             <div className="flex gap-1">
               <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></span>
               <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:200ms]"></span>
               <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:400ms]"></span>
             </div>
             نبراس جاي يفكر...
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Bar */}
      <div className="p-4 md:p-6 bg-white border-t border-slate-100 relative">
        <div className="max-w-4xl mx-auto flex items-end gap-3">

          <div className="relative" ref={menuRef}>
            <button 
              type="button"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all shadow-lg ${isMenuOpen ? 'bg-slate-800 text-white rotate-45' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
            </button>

            {isMenuOpen && (
              <div className="absolute bottom-20 right-0 w-64 bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-4 animate-in slide-in-from-bottom-6 duration-300 z-50">
                <div className="space-y-1">
                  <label className="flex items-center gap-3 px-4 py-3.5 rounded-2xl hover:bg-blue-50 text-slate-700 cursor-pointer transition-all group">
                    <span className="text-2xl">📁</span>
                    <div className="flex flex-col">
                      <span className="text-sm font-black group-hover:text-blue-600">رفع كتاب</span>
                      <span className="text-[10px] text-slate-400">PDF فقط</span>
                    </div>
                    <input type="file" className="hidden" accept="application/pdf" onChange={handlePdfUpload} />
                  </label>

                  <div className="h-px bg-slate-100 my-2"></div>

                  <MenuOption icon="🗣️" title="سالفة عراقية" desc="شرح ممتع باللهجة" onClick={() => selectMode(InteractionMode.EXPLAIN)} />
                  <MenuOption icon="⚡" title="خلاصة سريعة" desc="أهم 5 نقاط" onClick={() => selectMode(InteractionMode.SUMMARY)} />
                  <MenuOption icon="🃏" title="بطاقات حفظ" desc="سؤال وجواب" onClick={() => selectMode(InteractionMode.FLASHCARDS)} />
                  <MenuOption icon="🎨" title="تخيل المادة" desc="توليد صورة" onClick={() => selectMode(InteractionMode.VISUALIZE)} />

                  <label className="flex items-center gap-3 px-4 py-3.5 rounded-2xl hover:bg-amber-50 text-slate-700 cursor-pointer transition-all group">
                    <span className="text-2xl">📸</span>
                    <div className="flex flex-col">
                      <span className="text-sm font-black group-hover:text-amber-600">صحح دفتري</span>
                      <span className="text-[10px] text-slate-400">تحليل صورة الحل</span>
                    </div>
                    <input type="file" className="hidden" accept="image/*" onChange={handleImageCapture} />
                  </label>
                </div>
              </div>
            )}
          </div>

          <form onSubmit={handleSendMessage} className="flex-1 flex flex-col gap-2">
            {pendingImage && (
              <div className="flex items-center gap-2 bg-blue-50 p-2 rounded-2xl border border-blue-100 self-start animate-in zoom-in duration-200">
                <img src={pendingImage.preview} className="w-10 h-10 rounded-xl object-cover" alt="Preview" />
                <span className="text-[10px] font-black text-blue-600">صورة الحل جاهزة</span>
                <button type="button" onClick={() => setPendingImage(null)} className="text-red-400 p-1">✕</button>
              </div>
            )}
            <div className="relative group">
              <textarea
                rows={1}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); } }}
                placeholder={activeMode !== InteractionMode.QA ? `وضع ${activeMode} نشط...` : "اسألني أي شي ببالك..."}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] py-5 px-7 pr-16 focus:outline-none focus:border-blue-500 focus:bg-white transition-all shadow-inner font-bold resize-none min-h-[64px] max-h-40 custom-scrollbar"
              />
              <button 
                type="button" 
                onClick={() => setIsLiveMode(true)}
                className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              </button>
            </div>
          </form>

          <button 
            onClick={handleSendMessage}
            disabled={isLoading || (!input.trim() && !pendingImage)}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-xl shadow-blue-100 hover:bg-blue-700 hover:-translate-y-0.5 disabled:bg-slate-200 disabled:shadow-none transition-all flex-shrink-0"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 rotate-180" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

const MenuOption = ({ icon, title, desc, onClick }: { icon: string; title: string; desc: string; onClick: () => void }) => (
  <button onClick={onClick} className="w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl hover:bg-slate-50 text-right transition-all group">
    <span className="text-2xl group-hover:scale-110 transition-transform">{icon}</span>
    <div className="flex flex-col">
      <span className="text-sm font-black text-slate-700">{title}</span>
      <span className="text-[10px] text-slate-400 font-bold">{desc}</span>
    </div>
  </button>
);

export default ChatInterface;

import React from 'react';
import { PDFData, ChatHistoryEntry } from '../types';

interface SidebarProps {
  currentPdf: PDFData | null;
  onClear: () => void;
  history: ChatHistoryEntry[];
  activeChatId: string | null;
  onSelectChat: (id: string) => void;
  onNewChat: () => void;
  onDeleteChat: (id: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentPdf, 
  onClear, 
  history, 
  activeChatId, 
  onSelectChat, 
  onNewChat,
  onDeleteChat
}) => {
  const formatDate = (dateStr: string) => {
    const d = new Date(dateStr);
    const today = new Date();
    if (d.toDateString() === today.toDateString()) return 'اليوم';
    return d.toLocaleDateString('ar-IQ');
  };

  // Group by date
  const groupedHistory = history.reduce((acc: any, chat) => {
    const date = formatDate(chat.timestamp);
    if (!acc[date]) acc[date] = [];
    acc[date].push(chat);
    return acc;
  }, {});

  return (
    <div className="hidden lg:flex flex-col w-72 bg-white border-l border-slate-200">
      <div className="p-4 border-b border-slate-100">
        <button 
          onClick={onNewChat}
          className="w-full bg-slate-800 text-white rounded-2xl py-3 px-4 flex items-center justify-between font-black hover:bg-slate-900 transition-all shadow-lg shadow-slate-200"
        >
          <span>محادثة جديدة</span>
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar">
        {history.length === 0 ? (
          <div className="p-8 text-center opacity-40">
             <span className="text-4xl block mb-2">💬</span>
             <p className="text-[10px] font-black uppercase tracking-widest">ماكو محادثات سابقة</p>
          </div>
        ) : (
          <div className="p-4 space-y-6">
            {Object.entries(groupedHistory).map(([date, chats]: [string, any]) => (
              <div key={date}>
                <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-3 px-2">{date}</h4>
                <div className="space-y-1">
                  {chats.map((chat: ChatHistoryEntry) => (
                    <div key={chat.id} className="group relative">
                      <button 
                        onClick={() => onSelectChat(chat.id)}
                        className={`w-full text-right px-3 py-3 rounded-xl transition-all text-sm font-bold flex items-center gap-3 ${
                          activeChatId === chat.id 
                            ? 'bg-blue-50 text-blue-700' 
                            : 'hover:bg-slate-50 text-slate-600'
                        }`}
                      >
                        <span className="flex-shrink-0 text-lg opacity-60">{chat.pdf ? '📖' : '💬'}</span>
                        <span className="truncate flex-1">{chat.title}</span>
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDeleteChat(chat.id); }}
