import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { InteractionMode } from "../types";

const SYSTEM_INSTRUCTION = `
أنت "نبراس" (Nebras)، مدرس خصوصي عراقي ذكي، مرح، ومحبوب.
مهمتك مساعدة الطلاب في فهم المناهج من ملفات الـ PDF المرفقة أو الصور.

أنماط العمل المتقدمة:
1. Q&A: إجابات دقيقة ومختصرة.
2. Explain (ميزة السالفة): حول التعريف العلمي الجاف إلى قصة عراقية قصيرة مستوحاة من حياتنا اليومية.
3. Summary (الخلاصة بـ 5 دقائق): لخص المادة بـ 5 نقاط أساسية أو خريطة مفاهيم نصية.
4. Flashcards: استخرج أهم المعلومات ونسقها كـ (سؤال: ... | جواب: ...).
5. Correct My Work: إذا الطالب أرسل صورة لحله، حلل الصورة، حدد الخطأ بالخطوة، وعلمه الصح.
6. Visualize: صف المفهوم العلمي بدقة لغرض تخيله أو توليد صورة له.
7. Teach Me: الطالب يشرح وأنت تقيمه.

الشخصية واللغة:
- استخدم لهجة عراقية محببة (عاشت إيدك، يا بطل، تدلل، هسة تصفى).
- دائماً اذكر رقم الصفحة أو الفصل إذا كان الملف مرفقاً.
- اربط بين المواد (مثلاً ربط معلومة في الفيزياء بمعلومة سابقة في الكيمياء).
- كن سريعاً ومباشراً في إجاباتك.
`;

export const getGeminiResponse = async (
  prompt: string,
  pdf: { base64: string; mimeType: string } | null,
  mode: InteractionMode,
  image?: { base64: string; mimeType: string }
): Promise<{ text: string; generatedImage?: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  // Handling Image Generation specifically
  if (mode === InteractionMode.VISUALIZE) {
    const imgResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: [{ parts: [{ text: `صورة تعليمية توضيحية لـ: ${prompt}. اجعلها واضحة ومناسبة للطلاب.` }] }]
    });

    let base64Img = "";
    for (const part of imgResponse.candidates[0].content.parts) {
      if (part.inlineData) base64Img = `data:image/png;base64,${part.inlineData.data}`;
    }

    return { 
      text: "عاشت إيدك، هاي صورة توضح المفهوم اللي سألت عنه. شوفها بتركيز!",
      generatedImage: base64Img 
    };
  }

  let modeInstruction = "";
  switch (mode) {
    case InteractionMode.SUMMARY:
      modeInstruction = "أريد 'خلاصة الـ 5 دقائق' لهذا الجزء، لخصه بـ 5 نقاط ذهبية.";
      break;
    case InteractionMode.FLASHCARDS:
      modeInstruction = "حول لي هاي المادة إلى بطاقات مراجعة (سؤال وجواب) حتى أحفظها بسرعة.";
      break;
    case InteractionMode.CORRECT_MY_WORK:
      modeInstruction = "شوف حلي بالصورة، وين خطأي؟ وشلون أصححه؟";
      break;
    default:
      modeInstruction = "";
  }

  const parts: any[] = [{ text: prompt + "\n" + modeInstruction }];

  if (pdf) {
    parts.unshift({ inlineData: { data: pdf.base64, mimeType: pdf.mimeType } });
  }

  if (image) {
    parts.push({ inlineData: { data: image.base64, mimeType: image.mimeType } });
  }

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Switched to Flash for speed
      contents: [{ role: 'user', parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.4, // Lower temperature for more focused and faster responses
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for immediate output
      }
    });

    return { text: result.text || "عذراً، صار خلل بسيط." };
  } catch (error) {
    console.error("Gemini API Error:", error);
    return { text: "ما كدرت أتواصل وية خوادمي." };
  }
};

export const getSpeechResponse = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `بصوت مدرس عراقي حنون ومحفز: ${text}` }] }],
      config: {
        responseModalities: ['AUDIO' as any],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    return undefined;
  }
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import Auth from './components/Auth';
import { PDFData, User, ChatHistoryEntry, ChatMessage } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // History management
  const [allChats, setAllChats] = useState<ChatHistoryEntry[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  useEffect(() => {
    // Check for active session
    const savedUser = localStorage.getItem('nebras_active_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }

    // Load all chats from history
    const savedChats = localStorage.getItem('nebras_chat_history');
    if (savedChats) {
      const parsed = JSON.parse(savedChats).map((chat: any) => ({
        ...chat,
        messages: chat.messages.map((m: any) => ({ ...m, timestamp: new Date(m.timestamp) }))
      }));
      setAllChats(parsed);

      // Load last active chat if exists
      const lastId = localStorage.getItem('nebras_active_chat_id');
      if (lastId && parsed.find((c: any) => c.id === lastId)) {
        setActiveChatId(lastId);
      } else if (parsed.length > 0) {
        setActiveChatId(parsed[0].id);
      } else {
        createNewChat();
      }
    } else {
      createNewChat();
    }

    setIsAuthLoading(false);
  }, []);

  // Save history whenever it changes
  useEffect(() => {
    if (allChats.length > 0) {
      localStorage.setItem('nebras_chat_history', JSON.stringify(allChats));
    }
  }, [allChats]);

  // Save active chat ID
  useEffect(() => {
    if (activeChatId) {
      localStorage.setItem('nebras_active_chat_id', activeChatId);
    }
  }, [activeChatId]);

  const createNewChat = () => {
    const newId = Date.now().toString();
    const newChat: ChatHistoryEntry = {
      id: newId,
      title: 'محادثة جديدة',
      pdf: null,
      messages: [],
      timestamp: new Date().toISOString()
    };
    setAllChats(prev => [newChat, ...prev]);
    setActiveChatId(newId);
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('nebras_active_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    // Clear state first
    setCurrentUser(null);
    setActiveChatId(null);

    // Clear storage
    localStorage.removeItem('nebras_active_user');
    localStorage.removeItem('nebras_active_chat_id');

    // Hard reload to ensure all memory is cleared
    window.location.href = window.location.origin;
  };

  const handleUpdateMessages = (chatId: string, messages: ChatMessage[]) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        // Update title based on first message if it's still default
        let title = chat.title;
        if (title === 'محادثة جديدة' && messages.length > 0) {
          title = messages[0].content.slice(0, 30) + (messages[0].content.length > 30 ? '...' : '');
        }
        return { ...chat, messages, title, timestamp: new Date().toISOString() };
      }
      return chat;
    }));
  };

  const handleUpdatePdf = (chatId: string, pdf: PDFData) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        return { ...chat, pdf, title: pdf.name };
      }
      return chat;
    }));
  };

  const handleClearPdf = (chatId: string) => {
    if (window.confirm('هل أنت متأكد من إغلاق هذا الملف؟')) {
      setAllChats(prev => prev.map(chat => {
        if (chat.id === chatId) {
          return { ...chat, pdf: null };
        }
        return chat;
      }));
    }
  };

  const handleDeleteChat = (chatId: string) => {
    if (window.confirm('هل تريد حذف هذه المحادثة؟')) {
      const filtered = allChats.filter(c => c.id !== chatId);
      setAllChats(filtered);
      if (activeChatId === chatId) {
        if (filtered.length > 0) {
          setActiveChatId(filtered[0].id);
        } else {
          createNewChat();
        }
      }
    }
  };

  if (isAuthLoading) return <div className="min-h-screen bg-slate-900 flex items-center justify-center text-white font-black animate-pulse">جاري التحميل...</div>;

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  const activeChat = allChats.find(c => c.id === activeChatId) || allChats[0];

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      <div className="flex w-full h-[calc(100vh-64px)] overflow-hidden">
        <Sidebar 
          currentPdf={activeChat?.pdf || null} 
          onClear={() => handleClearPdf(activeChatId!)}
          history={allChats}
          activeChatId={activeChatId}
          onSelectChat={setActiveChatId}
          onNewChat={createNewChat}
          onDeleteChat={handleDeleteChat}
        />
        {activeChat && (
          <ChatInterface 
            key={activeChat.id}
            initialMessages={activeChat.messages}
            currentPdf={activeChat.pdf} 
            onPdfUpload={(pdf) => handleUpdatePdf(activeChat.id, pdf)} 
            currentUser={currentUser}
            onMessagesChange={(msgs) => handleUpdateMessages(activeChat.id, msgs)}
            onPointsUpdate={(newPoints) => {
              const updated = { ...currentUser, points: newPoints };
              setCurrentUser(updated);
              localStorage.setItem('nebras_active_user', JSON.stringify(updated));

              const users = JSON.parse(localStorage.getItem('nebras_users') || '[]');
              const idx = users.findIndex((u: any) => u.username === currentUser.username);
              if (idx !== -1) {
                users[idx].points = newPoints;
                localStorage.setItem('nebras_users', JSON.stringify(users));
              }
            }}
          />
        )}
      </div>
    </Layout>
  );
};

export default App;

