import React, { useState } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const trimmedUsername = username.trim();
    const trimmedPassword = password.trim();

    if (!trimmedUsername || !trimmedPassword) {
      setError('يرجى ملء جميع الحقول عيني.');
      return;
    }

    const storedUsers = JSON.parse(localStorage.getItem('nebras_users') || '[]');

    if (isLogin) {
      const user = storedUsers.find((u: any) => u.username === trimmedUsername && u.password === trimmedPassword);
      if (user) {
        onLogin({ username: user.username, points: user.points, joinedAt: user.joinedAt });
      } else {
        setError('اسم المستخدم أو كلمة المرور خطأ. تأكد من المعلومات.');
      }
    } else {
      if (storedUsers.find((u: any) => u.username === trimmedUsername)) {
        setError('اسم المستخدم هذا موجود مسبقاً، جرب غيره.');
        return;
      }
      const newUser = {
        username: trimmedUsername,
        password: trimmedPassword,
        points: 100, // Initial reward
        joinedAt: new Date().toISOString()
      };
      const updatedUsers = [...storedUsers, newUser];
      localStorage.setItem('nebras_users', JSON.stringify(updatedUsers));
      onLogin({ username: newUser.username, points: newUser.points, joinedAt: newUser.joinedAt });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-600 via-indigo-700 to-slate-900 p-4 font-['Tajawal']">
      <div className="bg-white/95 backdrop-blur-xl w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden p-8 md:p-12 animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-4xl font-black shadow-xl mx-auto mb-6 rotate-3">
            ن
          </div>
          <h1 className="text-3xl font-black text-slate-800 mb-2">أهلاً بك في نبراس</h1>
          <p className="text-slate-500 font-bold">رفيقك الذكي في مشوار النجاح</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {error && (
            <div className="bg-red-50 border-r-4 border-red-500 p-4 text-red-700 text-sm font-bold rounded-xl animate-bounce">
              {error}
            </div>
          )}

          <div>
            <label className="block text-slate-700 text-sm font-black mb-2 px-1">اسم المستخدم</label>
            <input
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-6 focus:outline-none focus:border-blue-500 focus:bg-white transition-all font-bold"
              placeholder="مثلاً: احمد البطل"
              required
            />
          </div>

          <div>
            <label className="block text-slate-700 text-sm font-black mb-2 px-1">كلمة المرور</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-6 focus:outline-none focus:border-blue-500 focus:bg-white transition-all font-bold"
              placeholder="••••••••"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-blue-200 hover:bg-blue-700 hover:-translate-y-1 active:scale-95 transition-all"
          >
            {isLogin ? 'تسجيل الدخول' : 'إنشاء حساب جديد'}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button
            onClick={() => {
              setIsLogin(!isLogin);
              setError('');
            }}
            className="text-blue-600 font-black hover:underline"
          >
            {isLogin ? 'ما عندك حساب؟ سجل هسة' : 'عندك حساب؟ سجل دخولك'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import Auth from './components/Auth';
import { PDFData, User, ChatHistoryEntry, ChatMessage } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // History management
  const [allChats, setAllChats] = useState<ChatHistoryEntry[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  useEffect(() => {
    // 1. Load active user
    const savedUser = localStorage.getItem('nebras_active_user');
    if (savedUser) {
      try {
        setCurrentUser(JSON.parse(savedUser));
      } catch (e) {
        localStorage.removeItem('nebras_active_user');
      }
    }

    // 2. Load all chats from history
    const savedChats = localStorage.getItem('nebras_chat_history');
    if (savedChats) {
      try {
        const parsed = JSON.parse(savedChats).map((chat: any) => ({
          ...chat,
          messages: (chat.messages || []).map((m: any) => ({ ...m, timestamp: new Date(m.timestamp) }))
        }));
        setAllChats(parsed);

        // Load last active chat
        const lastId = localStorage.getItem('nebras_active_chat_id');
        if (lastId && parsed.find((c: any) => c.id === lastId)) {
          setActiveChatId(lastId);
        } else if (parsed.length > 0) {
          setActiveChatId(parsed[0].id);
        } else {
          createNewChat();
        }
      } catch (e) {
        console.error("Failed to parse history", e);
        localStorage.removeItem('nebras_chat_history');
        createNewChat();
      }
    } else {
      createNewChat();
    }

    setIsAuthLoading(false);
  }, []);

  // Persistent saving of all chats
  useEffect(() => {
    if (allChats.length >= 0 && !isAuthLoading) {
      localStorage.setItem('nebras_chat_history', JSON.stringify(allChats));
    }
  }, [allChats, isAuthLoading]);

  // Save active chat ID
  useEffect(() => {
    if (activeChatId && !isAuthLoading) {
      localStorage.setItem('nebras_active_chat_id', activeChatId);
    }
  }, [activeChatId, isAuthLoading]);

  const createNewChat = () => {
    const newId = Date.now().toString();
    const newChat: ChatHistoryEntry = {
      id: newId,
      title: 'محادثة جديدة',
      pdf: null,
      messages: [],
      timestamp: new Date().toISOString()
    };
    setAllChats(prev => [newChat, ...prev]);
    setActiveChatId(newId);
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('nebras_active_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (!window.confirm('متأكد تريد تطلع؟')) return;

    // Clear everything from storage except users database
    localStorage.removeItem('nebras_active_user');
    localStorage.removeItem('nebras_active_chat_id');
    localStorage.removeItem('nebras_current_pdf');

    // Reset state locally
    setCurrentUser(null);
    setActiveChatId(null);
    setAllChats([]);

    // Force reset the whole app
    window.location.href = window.location.pathname + window.location.search;
  };

  const handleUpdateMessages = (chatId: string, messages: ChatMessage[]) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        let title = chat.title;
        if ((title === 'محادثة جديدة' || !title) && messages.length > 0) {
          const firstUserMsg = messages.find(m => m.role === 'user');
          if (firstUserMsg) {
            title = firstUserMsg.content.slice(0, 30) + (firstUserMsg.content.length > 30 ? '...' : '');
          }
        }
        return { ...chat, messages, title, timestamp: new Date().toISOString() };
      }
      return chat;
    }));
  };

  const handleUpdatePdf = (chatId: string, pdf: PDFData) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        return { ...chat, pdf, title: pdf.name };
      }
      return chat;
    }));
  };

  const handleClearPdf = (chatId: string) => {
    if (window.confirm('متأكد تريد تسد هذا الملف؟')) {
      setAllChats(prev => prev.map(chat => {
        if (chat.id === chatId) {
          return { ...chat, pdf: null };
        }
        return chat;
      }));
    }
  };

  const handleDeleteChat = (chatId: string) => {
    if (window.confirm('تريد تحذف هاي المحادثة نهائياً؟')) {
      const filtered = allChats.filter(c => c.id !== chatId);
      setAllChats(filtered);
      if (activeChatId === chatId) {
        if (filtered.length > 0) {
          setActiveChatId(filtered[0].id);
        } else {
          createNewChat();
        }
      }
    }
  };

  if (isAuthLoading) return (
    <div className="min-h-screen bg-white flex flex-col items-center justify-center font-black gap-4">
      <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-blue-600 animate-pulse">جاري تحضير نبراس...</p>
    </div>
  );

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  const activeChat = allChats.find(c => c.id === activeChatId) || allChats[0];

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      <div className="flex w-full h-[calc(100vh-64px)] overflow-hidden">
        <Sidebar 
          currentPdf={activeChat?.pdf || null} 
          onClear={() => handleClearPdf(activeChatId!)}
          history={allChats}
          activeChatId={activeChatId}
          onSelectChat={setActiveChatId}
          onNewChat={createNewChat}
          onDeleteChat={handleDeleteChat}
        />
        {activeChat ? (
          <ChatInterface 
            key={activeChat.id} // Essential for re-mounting on chat switch
            initialMessages={activeChat.messages}
            currentPdf={activeChat.pdf} 
            onPdfUpload={(pdf) => handleUpdatePdf(activeChat.id, pdf)} 
            currentUser={currentUser}
            onMessagesChange={(msgs) => handleUpdateMessages(activeChat.id, msgs)}
            onPointsUpdate={(newPoints) => {
              const updated = { ...currentUser, points: newPoints };
              setCurrentUser(updated);
              localStorage.setItem('nebras_active_user', JSON.stringify(updated));

              // Also update in the master users list
              const allUsers = JSON.parse(localStorage.getItem('nebras_users') || '[]');
              const updatedUsers = allUsers.map((u: any) => u.username === updated.username ? { ...u, points: newPoints } : u);
              localStorage.setItem('nebras_users', JSON.stringify(updatedUsers));
            }}
          />
        ) : (
          <div className="flex-1 bg-slate-50 flex items-center justify-center text-slate-400 font-bold">
            اختر محادثة أو ابدأ وحدة جديدة
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { InteractionMode } from "../types";

const SYSTEM_INSTRUCTION = `
أنت "نبراس" (Nebras)، مدرس خصوصي عراقي ذكي وسريع جداً.
مهمتك مساعدة الطلاب في فهم المناهج من ملفات الـ PDF أو الصور.

القواعد الذهبية:
1. كن مختصراً جداً وسريعاً في إجاباتك.
2. استخدم اللهجة العراقية الشعبية المحببة.
3. لا تطل الكلام الزائد، ادخل بالموضوع فوراً.
4. اذكر رقم الصفحة إذا سألك الطالب عن مكان المعلومة.

أنماط العمل:
- Q&A: إجابات دقيقة ومباشرة.
- Explain (السالفة): شرح شعبي ممتع ومختصر.
- Summary: 5 نقاط فقط.
- Flashcards: (سؤال: ... | جواب: ...).
- Correct My Work: حدد الخطأ وصححه فوراً.
- Visualize: وصف قصير لتوليد صورة تعليمية.
`;

export const getGeminiResponse = async (
  prompt: string,
  pdf: { base64: string; mimeType: string } | null,
  mode: InteractionMode,
  image?: { base64: string; mimeType: string }
): Promise<{ text: string; generatedImage?: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  if (mode === InteractionMode.VISUALIZE) {
    try {
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [{ parts: [{ text: `صورة تعليمية بسيطة وواضحة جداً لـ: ${prompt}.` }] }]
      });

      let base64Img = "";
      for (const part of imgResponse.candidates[0].content.parts) {
        if (part.inlineData) base64Img = `data:image/png;base64,${part.inlineData.data}`;
      }

      return { 
        text: "تدلل، هاي الصورة توضح اللي طلبته.",
        generatedImage: base64Img 
      };
    } catch (e) {
      return { text: "صار عندي تعب بتوليد الصورة، اسألني عنها كلامياً." };
    }
  }

  let modeInstruction = "";
  switch (mode) {
    case InteractionMode.SUMMARY:
      modeInstruction = "[لخص المادة فوراً بـ 5 نقاط مختصرة جداً]";
      break;
    case InteractionMode.FLASHCARDS:
      modeInstruction = "[حول المادة لبطاقات مراجعة سريعة]";
      break;
    case InteractionMode.CORRECT_MY_WORK:
      modeInstruction = "[حلل الصورة وصحح الخطأ بأقل كلمات]";
      break;
    default:
      modeInstruction = "";
  }

  const parts: any[] = [{ text: `${prompt}\n${modeInstruction}` }];

  if (pdf) {
    parts.unshift({ inlineData: { data: pdf.base64, mimeType: pdf.mimeType } });
  }

  if (image) {
    parts.push({ inlineData: { data: image.base64, mimeType: image.mimeType } });
  }

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Fastest model available
      contents: [{ role: 'user', parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Near-zero for speed and directness
        thinkingConfig: { thinkingBudget: 0 } // No thinking delay
      }
    });

    return { text: result.text || "عذراً يا بطل، ما كدرت أسمعك زين." };
  } catch (error) {
    console.error("Gemini API Error:", error);
    return { text: "خطي ضعيف هسة، حاول مرة ثانية عيوني." };
  }
};

export const getSpeechResponse = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `بصوت عراقي حنون ومختصر: ${text}` }] }],
      config: {
        responseModalities: ['AUDIO' as any],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (e) {
    return undefined;
  }
};

export enum InteractionMode {
  QA = 'QA',
  EXPLAIN = 'EXPLAIN',
  QUIZ = 'QUIZ',
  TEACH_ME = 'TEACH_ME',
  SUMMARY = 'SUMMARY',
  FLASHCARDS = 'FLASHCARDS',
  CORRECT_MY_WORK = 'CORRECT_MY_WORK',
  VISUALIZE = 'VISUALIZE'
}

export type ThemeMode = 'light' | 'dark' | 'system';
export type AccentColor = 'blue' | 'emerald' | 'violet' | 'rose' | 'amber' | 'slate';

export interface UserSettings {
  theme: ThemeMode;
  accentColor: AccentColor;
}

export interface User {
  username: string;
  points: number;
  joinedAt: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
  mode?: InteractionMode;
  imageUrl?: string;
  generatedImageUrl?: string;
}

export interface PDFData {
  name: string;
  base64: string;
  mimeType: string;
}

export interface ChatHistoryEntry {
  id: string;
  title: string;
  pdf: PDFData | null;
  messages: ChatMessage[];
  timestamp: string;
}

