import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import Auth from './components/Auth';
import { PDFData, User, ChatHistoryEntry, ChatMessage, UserSettings } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // Settings management
  const [settings, setSettings] = useState<UserSettings>(() => {
    try {
      const saved = localStorage.getItem('nebras_settings');
      return saved ? JSON.parse(saved) : { theme: 'light', accentColor: 'blue' };
    } catch (e) {
      return { theme: 'light', accentColor: 'blue' };
    }
  });

  // History management
  const [allChats, setAllChats] = useState<ChatHistoryEntry[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  useEffect(() => {
    // 1. Load active user
    const savedUser = localStorage.getItem('nebras_active_user');
    if (savedUser) {
      try {
        const user = JSON.parse(savedUser);
        if (user && user.username) {
          setCurrentUser(user);
        }
      } catch (e) {
        localStorage.removeItem('nebras_active_user');
      }
    }

    // 2. Load all chats
    const savedChats = localStorage.getItem('nebras_chat_history');
    if (savedChats) {
      try {
        const parsed = JSON.parse(savedChats).map((chat: any) => ({
          ...chat,
          messages: (chat.messages || []).map((m: any) => ({ ...m, timestamp: new Date(m.timestamp) }))
        }));
        setAllChats(parsed);

        const lastId = localStorage.getItem('nebras_active_chat_id');
        if (lastId && parsed.find((c: any) => c.id === lastId)) {
          setActiveChatId(lastId);
        } else if (parsed.length > 0) {
          setActiveChatId(parsed[0].id);
        } else {
          createNewChat();
        }
      } catch (e) {
        localStorage.removeItem('nebras_chat_history');
        createNewChat();
      }
    } else {
      createNewChat();
    }

    setIsAuthLoading(false);
  }, []);

  // Save history
  useEffect(() => {
    if (!isAuthLoading && allChats.length >= 0) {
      localStorage.setItem('nebras_chat_history', JSON.stringify(allChats));
    }
  }, [allChats, isAuthLoading]);

  // Save settings
  useEffect(() => {
    localStorage.setItem('nebras_settings', JSON.stringify(settings));
  }, [settings]);

  // Save active chat ID
  useEffect(() => {
    if (!isAuthLoading && activeChatId) {
      localStorage.setItem('nebras_active_chat_id', activeChatId);
    }
  }, [activeChatId, isAuthLoading]);

  const createNewChat = () => {
    const newId = Date.now().toString();
    const newChat: ChatHistoryEntry = {
      id: newId,
      title: 'محادثة جديدة',
      pdf: null,
      messages: [],
      timestamp: new Date().toISOString()
    };
    setAllChats(prev => [newChat, ...prev]);
    setActiveChatId(newId);
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('nebras_active_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (!window.confirm('متأكد تريد تطلع؟')) return;

    // 1. Clear State
    setCurrentUser(null);
    setActiveChatId(null);
    setAllChats([]);

    // 2. Clear Critical Session Storage
    localStorage.removeItem('nebras_active_user');
    localStorage.removeItem('nebras_active_chat_id');
    localStorage.removeItem('nebras_current_pdf');

    // 3. Clear transient app state but keep the users database and settings
    // 4. Reload the page to reset everything
    window.location.reload();
  };

  const handleUpdateMessages = (chatId: string, messages: ChatMessage[]) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        let title = chat.title;
        if ((title === 'محادثة جديدة' || !title) && messages.length > 0) {
          const firstUserMsg = messages.find(m => m.role === 'user');
          if (firstUserMsg) {
            title = firstUserMsg.content.slice(0, 30) + (firstUserMsg.content.length > 30 ? '...' : '');
          }
        }
        return { ...chat, messages, title, timestamp: new Date().toISOString() };
      }
      return chat;
    }));
  };

  const handleUpdatePdf = (chatId: string, pdf: PDFData) => {
    setAllChats(prev => prev.map(chat => {
      if (chat.id === chatId) {
        return { ...chat, pdf, title: pdf.name };
      }
      return chat;
    }));
  };

  const handleClearPdf = (chatId: string) => {
    if (window.confirm('متأكد تريد تسد هذا الملف؟')) {
      setAllChats(prev => prev.map(chat => {
        if (chat.id === chatId) {
          return { ...chat, pdf: null };
        }
        return chat;
      }));
    }
  };

  const handleDeleteChat = (chatId: string) => {
    if (window.confirm('تريد تحذف هاي المحادثة نهائياً؟')) {
      const filtered = allChats.filter(c => c.id !== chatId);
      setAllChats(filtered);
      if (activeChatId === chatId) {
        if (filtered.length > 0) {
          setActiveChatId(filtered[0].id);
        } else {
          createNewChat();
        }
      }
    }
  };

  if (isAuthLoading) return (
    <div className="min-h-screen bg-white flex flex-col items-center justify-center font-black gap-4">
      <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-blue-600 animate-pulse">جاري تحضير نبراس...</p>
    </div>
  );

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  const activeChat = allChats.find(c => c.id === activeChatId) || allChats[0];

  return (
    <Layout user={currentUser} onLogout={handleLogout} settings={settings}>
      <div className="flex w-full h-[calc(100vh-64px)] overflow-hidden">
        <Sidebar 
          currentPdf={activeChat?.pdf || null} 
          onClear={() => handleClearPdf(activeChatId!)}
          history={allChats}
          activeChatId={activeChatId}
          onSelectChat={setActiveChatId}
          onNewChat={createNewChat}
          onDeleteChat={handleDeleteChat}
          settings={settings}
        />
        {activeChat ? (
          <ChatInterface 
            key={activeChat.id}
            initialMessages={activeChat.messages}
            currentPdf={activeChat.pdf} 
            onPdfUpload={(pdf) => handleUpdatePdf(activeChat.id, pdf)} 
            currentUser={currentUser}
            settings={settings}
            onSettingsChange={setSettings}
            onMessagesChange={(msgs) => handleUpdateMessages(activeChat.id, msgs)}
            onPointsUpdate={(newPoints) => {
              const updated = { ...currentUser, points: newPoints };
              setCurrentUser(updated);
              localStorage.setItem('nebras_active_user', JSON.stringify(updated));
              const allUsers = JSON.parse(localStorage.getItem('nebras_users') || '[]');
              const updatedUsers = allUsers.map((u: any) => u.username === updated.username ? { ...u, points: newPoints } : u);
              localStorage.setItem('nebras_users', JSON.stringify(updatedUsers));
            }}
          />
        ) : (
          <div className="flex-1 bg-slate-50 dark:bg-slate-900 flex items-center justify-center text-slate-400 font-bold">
            اختر محادثة أو ابدأ وحدة جديدة
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    // Give it a tiny delay for better UX
    setTimeout(() => {
      const trimmedUsername = username.trim();
      const trimmedPassword = password.trim();

      if (!trimmedUsername || !trimmedPassword) {
        setError('يرجى ملء جميع الحقول عيني.');
        setIsLoading(false);
        return;
      }

      let storedUsers = [];
      try {
        storedUsers = JSON.parse(localStorage.getItem('nebras_users') || '[]');
      } catch (e) {
        storedUsers = [];
      }

      if (isLogin) {
        const user = storedUsers.find((u: any) => 
          u.username === trimmedUsername && 
          u.password === trimmedPassword
        );

        if (user) {
          onLogin({ username: user.username, points: user.points, joinedAt: user.joinedAt });
        } else {
          setError('اسم المستخدم أو كلمة المرور غير صحيحة. تأكد منها يا بطل.');
        }
      } else {
        if (storedUsers.find((u: any) => u.username === trimmedUsername)) {
          setError('اسم المستخدم هذا محجوز مسبقاً، جرب غيره عيوني.');
          setIsLoading(false);
          return;
        }

        const newUser = {
          username: trimmedUsername,
          password: trimmedPassword,
          points: 100,
          joinedAt: new Date().toISOString()
        };

        const updatedUsers = [...storedUsers, newUser];
        localStorage.setItem('nebras_users', JSON.stringify(updatedUsers));
        onLogin({ username: newUser.username, points: newUser.points, joinedAt: newUser.joinedAt });
      }
      setIsLoading(false);
    }, 400);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-600 via-indigo-700 to-slate-900 p-4 font-['Tajawal']">
      <div className="bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden p-8 md:p-12 animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-4xl font-black shadow-xl mx-auto mb-6 rotate-3">
            ن
          </div>
          <h1 className="text-3xl font-black text-slate-800 dark:text-slate-100 mb-2">نبراس</h1>
          <p className="text-slate-500 dark:text-slate-400 font-bold">مشوار النجاح يبدأ بكلمة</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {error && (
            <div className="bg-red-50 dark:bg-red-900/20 border-r-4 border-red-500 p-4 text-red-700 dark:text-red-400 text-sm font-bold rounded-xl animate-shake">
              {error}
            </div>
          )}

          <div>
            <label className="block text-slate-700 dark:text-slate-300 text-sm font-black mb-2 px-1">اسم المستخدم</label>
            <input
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl py-4 px-6 focus:outline-none focus:border-blue-500 focus:bg-white dark:focus:bg-slate-700 dark:text-white transition-all font-bold"
              placeholder="مثلاً: احمد البطل"
              disabled={isLoading}
              required
            />
          </div>

          <div>
            <label className="block text-slate-700 dark:text-slate-300 text-sm font-black mb-2 px-1">كلمة المرور</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl py-4 px-6 focus:outline-none focus:border-blue-500 focus:bg-white dark:focus:bg-slate-700 dark:text-white transition-all font-bold"
              placeholder="••••••••"
              disabled={isLoading}
              required
            />
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-blue-200 dark:shadow-none hover:bg-blue-700 hover:-translate-y-1 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            {isLoading ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                جاري التحميل...
              </>
            ) : (
              isLogin ? 'تسجيل الدخول' : 'إنشاء حساب جديد'
            )}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button
            onClick={() => {
              setIsLogin(!isLogin);
              setError('');
            }}
            disabled={isLoading}
            className="text-blue-600 dark:text-blue-400 font-black hover:underline disabled:opacity-50"
          >
            {isLogin ? 'ما عندك حساب؟ سجل هسة' : 'عندك حساب؟ سجل دخولك'}
          </button>
        </div>
      </div>
    </div>
  );
};

